async function login(){const email=emailEl.value.trim(),senha=senhaEl.value;if(!email||!senha){setLoginStatus("Informe email e senha.",true);return}const body=new URLSearchParams();body.append("username",email);body.append("password",senha);try{const res=await fetch(baseUrl+"/login",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body});const data=await res.json();if(!res.ok){setLoginStatus(data.detail||"Falha no login.",true);return}setToken(data.access_token||"");setLoginStatus("Login efetuado com sucesso.",false);await carregarSessao()}catch{setLoginStatus("Erro de conexao com backend.",true)}}
async function signupRequestCode(){const p={nome:signupNomeEl.value.trim(),email:signupEmailEl.value.trim(),senha:signupSenhaEl.value};if(!p.nome||!p.email||!p.senha){setLoginStatus("Preencha nome, email e senha para cadastrar.",true);return}if((p.senha||"").length<6){setLoginStatus("A senha deve ter no minimo 6 digitos.",true);return}try{const{res,data}=await postJson("/signup/request-code",p);if(!res.ok){setLoginStatus(data.detail||"Falha ao enviar codigo.",true);return}setLoginStatus(data.detail||"Codigo enviado por e-mail.",false)}catch{setLoginStatus("Erro de conexao ao solicitar codigo.",true)}}
async function signupConfirm(){const p={nome:signupNomeEl.value.trim(),email:signupEmailEl.value.trim(),senha:signupSenhaEl.value,codigo:signupCodigoEl.value.trim()};if(!p.nome||!p.email||!p.senha||!p.codigo){setLoginStatus("Preencha todos os campos do cadastro.",true);return}if((p.senha||"").length<6){setLoginStatus("A senha deve ter no minimo 6 digitos.",true);return}try{const{res,data}=await postJson("/signup/confirm",p);if(!res.ok){setLoginStatus(data.detail||"Falha ao confirmar cadastro.",true);return}setToken(data.access_token||"");setLoginStatus(data.detail||"Cadastro confirmado.",false);await carregarSessao()}catch{setLoginStatus("Erro de conexao ao confirmar cadastro.",true)}}
async function forgotRequestCode(){const email=forgotEmailEl.value.trim();if(!email){setLoginStatus("Informe o e-mail para recuperar a senha.",true);return}try{const{res,data}=await postJson("/password/forgot",{email});if(!res.ok){setLoginStatus(data.detail||"Falha ao enviar codigo.",true);return}setLoginStatus(data.detail||"Codigo enviado para o e-mail.",false)}catch{setLoginStatus("Erro de conexao ao solicitar recuperacao.",true)}}
async function forgotResetPassword(){const p={email:forgotEmailEl.value.trim(),codigo:forgotCodigoEl.value.trim(),nova_senha:forgotSenhaEl.value};if(!p.email||!p.codigo||!p.nova_senha){setLoginStatus("Preencha email, codigo e nova senha.",true);return}if((p.nova_senha||"").length<6){setLoginStatus("A senha deve ter no minimo 6 digitos.",true);return}try{const{res,data}=await postJson("/password/reset",p);if(!res.ok){setLoginStatus(data.detail||"Falha ao redefinir senha.",true);return}setLoginStatus(data.detail||"Senha redefinida. Faca login.",false);showPanel(panelLogin);emailEl.value=p.email}catch{setLoginStatus("Erro de conexao ao redefinir senha.",true)}}
const hideAllPanels=()=>{if(preserveProtectedGrantOnHide){preserveProtectedGrantOnHide=false}else{clearProtectedGrants()}usersDetachOverlay();cenarioPanel.classList.add("hidden");materiaisPanel.classList.add("hidden");proc.panel.classList.add("hidden");proc.novoPanel.classList.add("hidden");usersPanel.classList.add("hidden");if(sa&&sa.panel){sa.panel.classList.add("hidden")}if(prot&&prot.panel){prot.panel.classList.add("hidden")}if(ctrlProt&&ctrlProt.panel){ctrlProt.panel.classList.add("hidden")}if(convPlanCfg&&convPlanCfg.panel){convPlanCfg.panel.classList.add("hidden")}if(convPlanCalCfg&&convPlanCalCfg.panel){convPlanCalCfg.panel.classList.add("hidden")}if(prestCfg&&prestCfg.panel){prestCfg.panel.classList.add("hidden")}if(unidadeCfg&&unidadeCfg.panel){unidadeCfg.panel.classList.add("hidden")}if(pgen&&pgen.panel){pgen.panel.classList.add("hidden")}if(ficha&&ficha.panel){ficha.panel.classList.add("hidden")}if(fichaMenuPac)fichaMenuPacFechar();if(cc){cc.panel.classList.add("hidden")}if(rcc){rcc.panel.classList.add("hidden");rcc.viewPanel.classList.add("hidden")}if(fcx&&fcx.panel){fcx.panel.classList.add("hidden")}if(dash&&dash.panel){dash.panel.classList.add("hidden")}if(plano){plano.panel.classList.add("hidden")}if(aux){aux.panel.classList.add("hidden")}if(agendaContatos&&agendaContatos.panel){agendaContatos.panel.classList.add("hidden")}if(agendaLegado&&agendaLegado.panel){agendaLegado.panel.classList.add("hidden")}if(agendaSemana&&agendaSemana.panel){agendaSemana.panel.classList.add("hidden")}if(cid&&cid.panel){cid.panel.classList.add("hidden")}usersStopRefresh();usersFecharModal();usersFecharModalSenha();usersFecharPermissoes();workspaceEmpty.classList.remove("hidden")};
