function ensureChromeTypographyStyles(){if(document.getElementById("screen-standard-typography"))return;const style=document.createElement("style");style.id="screen-standard-typography";style.textContent=`.panel-standardized,.modal-standardized{font:12px Tahoma,sans-serif;color:#000}.panel-standardized .panel-standard-title,.panel-standardized .panel-title,.panel-standardized .pgen-title,.panel-standardized .aux-window-title,.modal-standardized .modal-standard-title,.modal-standardized .modal-title,.modal-standardized .cc-modal-title,.modal-standardized .cad-modal-title{font-family:Tahoma,sans-serif}.panel-standardized label,.panel-standardized input,.panel-standardized select,.panel-standardized textarea,.panel-standardized button,.panel-standardized table,.panel-standardized th,.panel-standardized td,.panel-standardized span,.panel-standardized div,.modal-standardized label,.modal-standardized input,.modal-standardized select,.modal-standardized textarea,.modal-standardized button,.modal-standardized table,.modal-standardized th,.modal-standardized td,.modal-standardized span,.modal-standardized div{font-family:Tahoma,sans-serif}.panel-standardized label,.panel-standardized input,.panel-standardized select,.panel-standardized textarea,.panel-standardized th,.panel-standardized td,.panel-standardized .money,.panel-standardized .num-box,.panel-standardized .nproc-box,.panel-standardized .pgen-vinc-head span,.panel-standardized .pgen-vinc-table td,.modal-standardized label,.modal-standardized input,.modal-standardized select,.modal-standardized textarea,.modal-standardized th,.modal-standardized td{font-size:12px}.panel-standard-header,.modal-standard-header{cursor:move;user-select:none}.panel-standard-header button,.modal-standard-header button{cursor:pointer}`;document.head.appendChild(style)}
const chromeDragState={active:false,pointerId:null,target:null,startX:0,startY:0,offsetX:0,offsetY:0};
function chromeApplyDragOffset(el,x,y){if(!(el instanceof HTMLElement))return;el.dataset.dragX=String(x);el.dataset.dragY=String(y);el.style.transform=`translate(${x}px,${y}px)`}
function chromeResetDragOffset(el){if(!(el instanceof HTMLElement))return;delete el.dataset.dragX;delete el.dataset.dragY;el.style.transform=""}
function chromeDragMove(ev){if(!chromeDragState.active||!(chromeDragState.target instanceof HTMLElement))return;const x=Math.round(ev.clientX-chromeDragState.startX+chromeDragState.offsetX);const y=Math.round(ev.clientY-chromeDragState.startY+chromeDragState.offsetY);chromeApplyDragOffset(chromeDragState.target,x,y)}
function chromeDragStop(ev){if(!chromeDragState.active)return;const target=chromeDragState.target;if(ev&&chromeDragState.pointerId!=null&&target?.releasePointerCapture){try{target.releasePointerCapture(chromeDragState.pointerId)}catch{}}chromeDragState.active=false;chromeDragState.pointerId=null;chromeDragState.target=null;document.removeEventListener("pointermove",chromeDragMove,true);document.removeEventListener("pointerup",chromeDragStop,true);document.removeEventListener("pointercancel",chromeDragStop,true)}
function chromeDragStart(ev,target){if(!(target instanceof HTMLElement))return;if(ev.button!==0)return;if(ev.target instanceof HTMLElement&&ev.target.closest("button,input,select,textarea,a,[role='button'],label"))return;chromeDragState.active=true;chromeDragState.pointerId=typeof ev.pointerId==="number"?ev.pointerId:null;chromeDragState.target=target;chromeDragState.startX=ev.clientX;chromeDragState.startY=ev.clientY;chromeDragState.offsetX=Number(target.dataset.dragX||0);chromeDragState.offsetY=Number(target.dataset.dragY||0);if(chromeDragState.pointerId!=null&&target.setPointerCapture){try{target.setPointerCapture(chromeDragState.pointerId)}catch{}}document.addEventListener("pointermove",chromeDragMove,true);document.addEventListener("pointerup",chromeDragStop,true);document.addEventListener("pointercancel",chromeDragStop,true);ev.preventDefault()}
function ensureChromeDraggable(target,handle){if(!(target instanceof HTMLElement)||!(handle instanceof HTMLElement))return;if(handle.dataset.dragBound==="true")return;handle.dataset.dragBound="true";handle.addEventListener("dblclick",ev=>{if(ev.target instanceof HTMLElement&&ev.target.closest("button"))return;chromeResetDragOffset(target)});handle.addEventListener("pointerdown",ev=>chromeDragStart(ev,target))}
