function ensurePanelChrome(panel){if(!(panel instanceof HTMLElement)||!panel.matches('section[id$="-panel"]'))return;ensureChromeTypographyStyles();if(panel.querySelector(".ficha-titlebar")){applyPanelChromeInsets(panel);const fichaHeader=panel.querySelector(".ficha-titlebar");if(fichaHeader)ensureChromeDraggable(panel,fichaHeader);return}applyPanelChromeInsets(panel);panel.classList.add("panel-standardized");let header=panel.querySelector(".panel-standard-header");if(!header){header=document.createElement("div");header.className="panel-standard-header";panel.insertBefore(header,panel.firstChild)}let titleEl=directChildBySelector(panel,".panel-title,.pgen-title,.aux-window-title,.panel-standard-title");const headerTitle=header.querySelector(".panel-standard-title,.panel-title,.pgen-title,.aux-window-title");if(titleEl){if(headerTitle&&headerTitle!==titleEl&&headerTitle.dataset.generated==="true")headerTitle.remove();if(titleEl.parentElement!==header)header.insertBefore(titleEl,header.firstChild)}else if(!headerTitle){titleEl=document.createElement("div");titleEl.className="panel-title panel-standard-title";titleEl.dataset.generated="true";titleEl.textContent=PANEL_TITLE_DEFAULTS[panel.id]||"";header.appendChild(titleEl)}else titleEl=headerTitle;if(titleEl){titleEl.classList.add("panel-standard-title");if(!titleEl.textContent.trim())titleEl.textContent=PANEL_TITLE_DEFAULTS[panel.id]||""}const allButtons=Array.from(panel.querySelectorAll(".panel-close-x"));let closeBtn=allButtons.find(btn=>btn.parentElement===header)||allButtons[0]||null;allButtons.forEach(btn=>{if(btn!==closeBtn)btn.remove()});if(panel.id==="workspace-empty"){if(closeBtn)closeBtn.remove();return}if(!closeBtn){closeBtn=document.createElement("button");closeBtn.type="button";closeBtn.className="panel-close-x";closeBtn.textContent="X";closeBtn.title="Fechar";closeBtn.setAttribute("aria-label","Fechar tela");closeBtn.addEventListener("click",ev=>{ev.stopPropagation();closeWorkspacePanel(panel.id)})}if(closeBtn.parentElement!==header)header.appendChild(closeBtn);ensureChromeDraggable(panel,header)}
function syncPanelCloseButtons(root=document){const panels=[];if(root instanceof HTMLElement&&root.matches('section[id$="-panel"]'))panels.push(root);if(root&&root.querySelectorAll)root.querySelectorAll('section[id$="-panel"]').forEach(panel=>panels.push(panel));panels.forEach(ensurePanelChrome)}
function initPanelCloseButtons(){const workspace=document.querySelector(".workspace");if(!workspace)return;syncPanelCloseButtons(workspace);const obs=new MutationObserver(muts=>{muts.forEach(m=>{m.addedNodes.forEach(node=>{if(!(node instanceof HTMLElement))return;const ownPanel=node.matches&&node.matches('section[id$="-panel"]')?node:null;const parentPanel=node.closest&&node.closest('section[id$="-panel"]');if(ownPanel)syncPanelCloseButtons(ownPanel);if(parentPanel)syncPanelCloseButtons(parentPanel);if(node.querySelectorAll)syncPanelCloseButtons(node)})})});obs.observe(workspace,{childList:true,subtree:true})}
function ensureModalChrome(modal){if(!(modal instanceof HTMLElement))return;ensureChromeTypographyStyles();const backdrop=modal.closest(".modal-backdrop,.ficha-menu-backdrop,.cc-modal-backdrop,.cad-modal-backdrop,.prot-modal-backdrop");if(!backdrop||!backdrop.id)return;applyModalChromeInsets(modal,backdrop.id);if(modal.querySelector(".ficha-menu-top")||modal.querySelector(".proc-tabela-titlebar")){modal.classList.add("modal-standardized");return}modal.classList.add("modal-standardized");let header=directChildBySelector(modal,".modal-header,.modal-standard-header");let titleEl=directChildBySelector(modal,".modal-title,.cc-modal-title,.cad-modal-title");if(header){header.classList.add("modal-standard-header");if(!titleEl)titleEl=header.querySelector(".modal-title,.cc-modal-title,.cad-modal-title,.modal-standard-title")}else{header=document.createElement("div");header.className="modal-standard-header";modal.insertBefore(header,modal.firstChild);if(titleEl)header.appendChild(titleEl)}if(!titleEl){titleEl=document.createElement("div");titleEl.className="modal-title modal-standard-title";titleEl.dataset.generated="true";titleEl.textContent=modalTitleByBackdropId(backdrop.id);header.insertBefore(titleEl,header.firstChild)}titleEl.classList.add("modal-standard-title");if(!titleEl.textContent.trim())titleEl.textContent=modalTitleByBackdropId(backdrop.id);const closeSelectors=".modal-close-x,#materiais-tabela-modal-close,.proc-tabela-x,#ficha-menu-close";const buttons=Array.from(header.querySelectorAll(closeSelectors));let closeBtn=buttons[0]||null;buttons.slice(1).forEach(btn=>btn.remove());if(closeBtn){closeBtn.classList.add("modal-close-x")}else{closeBtn=document.createElement("button");closeBtn.type="button";closeBtn.className="modal-close-x";closeBtn.textContent="X";closeBtn.title="Fechar";closeBtn.setAttribute("aria-label","Fechar janela");closeBtn.addEventListener("click",ev=>{ev.stopPropagation();closeModalByBackdropId(backdrop.id)});header.appendChild(closeBtn)}ensureChromeDraggable(modal,header)}
function syncModalHeaders(root=document.body){if(!root)return;const modals=[];const selectors=['.modal-backdrop .modal','#cc-modal-backdrop .cc-modal','#ficha-menu-backdrop .ficha-menu-modal','#cad-modal-backdrop .cad-modal','#prot-modal-backdrop .prot-modal'];if(root instanceof HTMLElement){selectors.forEach(sel=>{if(root.matches&&root.matches(sel))modals.push(root);if(root.querySelectorAll)root.querySelectorAll(sel).forEach(modal=>modals.push(modal))})}else if(root.querySelectorAll)selectors.forEach(sel=>root.querySelectorAll(sel).forEach(modal=>modals.push(modal)));modals.forEach(ensureModalChrome)}
function initModalChrome(){if(!document.body)return;syncModalHeaders(document.body);const obs=new MutationObserver(muts=>{muts.forEach(m=>{m.addedNodes.forEach(node=>{if(!(node instanceof HTMLElement))return;syncModalHeaders(node)})})});obs.observe(document.body,{childList:true,subtree:true})}
const formatDec2=(v)=>Number(v||0).toLocaleString("pt-BR",{minimumFractionDigits:2,maximumFractionDigits:2});
const formatDec2Dot=(v)=>{const n=Number(v||0);return Number.isFinite(n)?n.toFixed(2):"0.00"};
const parseMaterialNumber=(v)=>{const s=String(v??"").trim().replace(",",".");if(!s)return 0;const n=Number(s);if(!Number.isFinite(n))throw new Error("NÃºmero invÃ¡lido");return n};
