const materiaisListaAtual=()=>materiaisListasCache.find(x=>Number(x.id)===materiaisListaIdAtual())||null;
const materiaisSetTotal=()=>{m.lblTotal.textContent="Total de Materiais: "+m.tbody.querySelectorAll("tr").length};
