const materiaisLimparTabela=()=>{materiaisCache=[];materialSelecionadoId=null;m.tbody.innerHTML="";materiaisSetTotal()};
const materiaisRender=()=>{m.tbody.innerHTML=materiaisCache.map(x=>`<tr data-id="${x.id}"><td>${esc(x.codigo)}</td><td>${esc(x.nome)}</td><td>${formatDec2(x.preco)}</td><td>${formatDec2(x.relacao)}</td><td>${formatDec2(x.custo)}</td></tr>`).join("");materiaisSetTotal()};
