function materiaisTabelaAtualIndice(){const atual=materiaisListaAtual();return String(Number(atual?.nro_indice||255))}
async function materiaisTabelaAbrirModal(modo){if(!materiaisTabelaModal.backdrop||!materiaisTabelaModal.nome||!materiaisTabelaModal.cboIndice)return;const abrirAlteracao=modo==="altera";const listaId=materiaisListaIdAtual();if(abrirAlteracao&&!listaId){window.alert("Selecione uma tabela para alterar.");return}materiaisTabelaModalModo=abrirAlteracao?"altera":"nova";materiaisTabelaModalListaId=abrirAlteracao?listaId:0;if(materiaisTabelaModal.title)materiaisTabelaModal.title.textContent=abrirAlteracao?"Altera tabela de materiais":"Nova tabela de materiais";if(materiaisTabelaModal.label)materiaisTabelaModal.label.textContent="Nome";materiaisTabelaModal.nome.value=abrirAlteracao?materiaisTabelaAtualNome():"";await materiaisCarregarIndicesTabela(abrirAlteracao?materiaisTabelaAtualIndice():255);materiaisTabelaModal.backdrop.classList.remove("hidden");materiaisTabelaModal.nome.focus();materiaisTabelaModal.nome.select()}
async function materiaisTabelaSalvarModal(){const nome=String(materiaisTabelaModal.nome?.value||"").trim();const nro_indice=String(materiaisTabelaModal.cboIndice?.value||255).trim();if(!nome){window.alert(materiaisTabelaModalModo==="altera"?"Informe o nome da tabela.":"Informe o nome da nova tabela.");return}if(materiaisTabelaModalModo==="altera"){const listaId=materiaisTabelaModalListaId||materiaisListaIdAtual();if(!listaId){window.alert("Selecione uma tabela para alterar.");return}const{res,data}=await requestJson("PATCH",`/materiais/listas/${listaId}`,{nome,nro_indice},true);if(!res.ok){window.alert(data.detail||"Falha ao alterar tabela.");return}await materiaisCarregarListas(data.id);footerMsg.textContent="Tabela alterada com sucesso."}else{const{res,data}=await requestJson("POST","/materiais/listas",{nome,nro_indice},true);if(!res.ok){window.alert(data.detail||"Falha ao criar tabela.");return}await materiaisCarregarListas(data.id);footerMsg.textContent="Tabela criada com sucesso."}materiaisTabelaFecharModal()}
