async function materiaisExcluirTabela(){const listaId=materiaisListaIdAtual();if(!listaId)return;const atual=m.cboListas.options[m.cboListas.selectedIndex]?.textContent||"";if(!window.confirm(`Deseja realmente excluir a tabela '${atual}'?\n\nTodos os materiais desta tabela serao excluidos.`))return;const{res,data}=await requestJson("DELETE",`/materiais/listas/${listaId}`,undefined,true);if(!res.ok){window.alert(data.detail||"Falha ao excluir tabela.");return}await materiaisCarregarListas();footerMsg.textContent="Tabela excluida com sucesso."}
