function procRelatorioStorageKey(){return `brana_proc_relatorio_campos_v1_${String(sessaoAtual?.clinica_id||"global")}`}
function procRelatorioLerCamposMemorizados(){
  try{
    const raw=localStorage.getItem(procRelatorioStorageKey());
    if(!raw)return null;
    const data=JSON.parse(raw);
    if(!Array.isArray(data))return null;
    const permitidos=new Set(PROC_RELATORIO_CAMPOS_DISPONIVEIS);
    const selecionados=data.map(x=>String(x||"").trim()).filter(x=>x&&permitidos.has(x));
    return Array.from(new Set(selecionados))
  }catch{
    return null
  }
}
function procRelatorioMemorizarCampos(){
  if(!procRelatorio?.lstSelecionados)return;
  try{
    const selecionados=[...procRelatorio.lstSelecionados.options].map(opt=>String(opt.value||"").trim()).filter(Boolean);
    localStorage.setItem(procRelatorioStorageKey(),JSON.stringify(selecionados))
  }catch{}
}
