function procRelatorioAtualizarOrdem(){
  if(!procRelatorio?.cboOrdem||!procRelatorio?.lstSelecionados)return;
  const itens=[...procRelatorio.lstSelecionados.options].map(opt=>String(opt.value||"")).filter(Boolean);
  const atual=String(procRelatorio.cboOrdem.value||"");
  procRelatorio.cboOrdem.innerHTML=itens.map(item=>`<option value="${esc(item)}">${esc(item)}</option>`).join("");
  if(itens.length===0){
    procRelatorio.cboOrdem.innerHTML='<option value=""></option>';
    procRelatorio.cboOrdem.value="";
    return;
  }
  procRelatorio.cboOrdem.value=itens.includes(atual)?atual:itens[0]
}
function procRelatorioMover(origem,destino){
  const selecionados=[...origem.selectedOptions];
  if(selecionados.length===0)return;
  const valoresDestino=new Set([...destino.options].map(opt=>String(opt.value||"")));
  selecionados.forEach(opt=>{
    const valor=String(opt.value||"");
    if(!valoresDestino.has(valor)){
      destino.appendChild(new Option(opt.text,opt.value));
      valoresDestino.add(valor);
    }
    opt.remove();
  });
  procRelatorioAtualizarOrdem();
  procRelatorioMemorizarCampos()
}
