function procRelatorioResetar(){
  if(!procRelatorio)return;
  const tabelas=Array.isArray(procFiltros?.tabelas)?procFiltros.tabelas:[];
  const especialidades=Array.isArray(procFiltros?.especialidades)?procFiltros.especialidades:[];
  const baseTabelas=tabelas.length?tabelas:[{id:"1",nome:"Tabela Exemplo"}];
  procRelatorio.cboTabela.innerHTML=baseTabelas.map(x=>`<option value="${esc(String(x.id??""))}">${esc(String(x.nome??""))}</option>`).join("");
  procSetSelectValue(procRelatorio.cboTabela,String(proc.cboTabela?.value||baseTabelas[0]?.id||""));
  procRelatorio.cboEspecialidade.innerHTML=['<option value="">Todas</option>',...especialidades.map(x=>`<option value="${esc(String(x.codigo??""))}">${esc(String(x.nome??""))}</option>`)].join("");
  procSetSelectValue(procRelatorio.cboEspecialidade,String(proc.cboEspecialidade?.value||""));
  procRelatorio.chkEspecialidade.checked=false;
  procRelatorio.cboEspecialidade.disabled=true;
  const camposMemorizados=procRelatorioLerCamposMemorizados();
  const selecionados=Array.isArray(camposMemorizados)?camposMemorizados:[...PROC_RELATORIO_CAMPOS_PADRAO];
  const selecionadosSet=new Set(selecionados);
  const disponiveis=PROC_RELATORIO_CAMPOS_DISPONIVEIS.filter(item=>!selecionadosSet.has(item));
  procRelatorio.lstDisponiveis.innerHTML=disponiveis.map(item=>`<option value="${esc(item)}">${esc(item)}</option>`).join("");
  procRelatorio.lstSelecionados.innerHTML=selecionados.map(item=>`<option value="${esc(item)}">${esc(item)}</option>`).join("");
  procRelatorio.cboSaida.value="Tela";
  procRelatorio.radRetrato.checked=true;
  procRelatorio.radPaisagem.checked=false;
  procRelatorio.txtNome.value="RelatÃ³rio de tabela de procedimentos";
  procRelatorioAtualizarOrdem();
  procRelatorioMemorizarCampos();
  procRelatorioMostrarAba("geral");
}
