  if(cnfRelatorio.paperInfoLargura)cnfRelatorio.paperInfoLargura.textContent=Number(st.paperWidthCm||21).toFixed(1).replace(".",",");
  if(cnfRelatorio.paperImpAltura)cnfRelatorio.paperImpAltura.textContent=Number(st.paperHeightCm||29.7).toFixed(1).replace(".",",");
  if(cnfRelatorio.paperImpLargura)cnfRelatorio.paperImpLargura.textContent=Number(st.paperWidthCm||21).toFixed(1).replace(".",",");
