function cnfRelatorioAlterarFonte(){
  if(!cnfRelatorio||typeof window.easyFontAbrir!=="function")return;
  const sec=cnfRelatorio.state.sectionId||"titulo";
  const atual=cnfRelatorio.state.sectionStyles?.[sec]||cnfRelatorioPadrao().sectionStyles[sec];
  window.easyFontAbrir({
    initialValue:{
      family:String(atual.fontFamily||"Tahoma"),
      styleId:atual.bold?(atual.italic?"negrito-italico":"negrito"):(atual.italic?"italico":"normal"),
      size:Math.max(8,Math.min(72,Number(atual.fontSize||10))),
      color:String(atual.color||"#111111"),
      strike:!!atual.strike,
      underline:!!atual.underline,
      script:"Ocidental",
    },
    previewText:String(CNF_RELATORIO_SECOES.find(item=>item.id===sec)?.preview||"Titulo do relatorio"),
    onSave(valor){
      const styleId=typeof window.easyFontNormalizeStyleId==="function"?window.easyFontNormalizeStyleId(valor?.styleId):String(valor?.styleId||"normal");
      cnfRelatorio.state.sectionStyles[sec]={
        ...atual,
        fontFamily:String(valor?.family||atual.fontFamily||"Tahoma"),
        fontSize:Math.max(8,Math.min(72,Number(valor?.size||atual.fontSize||10)||10)),
        bold:styleId==="negrito"||styleId==="negrito-italico",
        italic:styleId==="italico"||styleId==="negrito-italico",
        color:String(valor?.color||atual.color||"#111111"),
        strike:!!valor?.strike,
        underline:!!valor?.underline,
      };
      cnfRelatorioSalvarEstado();
      cnfRelatorioAplicarPreview();
    }
  });
}
