async function etqAbrir(){
  etqEnsureUI();
  try{
    await etqCarregarDados();
    const existe=etqCfg.modelos.some(item=>Number(item.id)===Number(etqCfg.selectedId));
    if(!existe)etqCfg.selectedId=etqCfg.modelos[0]?.id||null;
    etqRender();
    etqCfg.backdrop.classList.remove("hidden");
  }catch(err){
    window.alert(err?.message||"Falha ao carregar modelos de etiqueta.");
  }
}
