function sysOptSelecionarAba(tabId){
  if(!sysOptCfg)return;
  sysOptCfg.tabAtual=tabId;
  sysOptCfg.tabs.forEach(btn=>btn.classList.toggle("active",btn.dataset.tab===tabId));
  sysOptCfg.panes.forEach(pane=>pane.classList.toggle("hidden",pane.dataset.pane!==tabId));
  const mapa={
    clinica:"ClÃ­nica carregada.",
    financeiro:"Financeiro carregado.",
    seguranca:"SeguranÃ§a carregada.",
    data:"Data carregada.",
    avancado:"AvanÃ§ado carregado."
  };
  footerMsg.textContent=mapa[tabId]||"OpÃ§Ãµes do sistema carregadas.";
}

function sysOptRenderSelects(){
  if(!sysOptCfg)return;
  const opts=sysOptCfg.options||{};
  const indices=Array.isArray(opts.indices)?opts.indices:[];
  const formatosData=Array.isArray(opts.formatos_data)?opts.formatos_data:[];
  const formatosEmail=Array.isArray(opts.formatos_email)?opts.formatos_email:[];
  const sistemasCaptura=Array.isArray(opts.sistemas_captura)?opts.sistemas_captura:[];
  const versoesWord=Array.isArray(opts.versoes_word)?opts.versoes_word:[];
  const tiposCobranca=Array.isArray(opts.tipos_cobranca)?opts.tipos_cobranca:[];
  const categorias=Array.isArray(opts.categorias_financeiras)?opts.categorias_financeiras:[];

  if(sysOptCfg.cboClinicaUf){
    const ufAtual=String(sysOptCfg.cboClinicaUf.value||"");
    sysOptCfg.cboClinicaUf.innerHTML=`<option value=""></option>`+FICHA_UFS_PADRAO.map(item=>`<option value="${item}">${item}</option>`).join("");
    if(ufAtual&&FICHA_UFS_PADRAO.includes(ufAtual))sysOptCfg.cboClinicaUf.value=ufAtual;
  }

  const renderIndice=el=>{
    procPreencherSelect(el,indices,{
      placeholder:null,
      valueFrom:(item)=>item?.id??"",
      labelFrom:(item)=>`${item?.sigla??""} - ${item?.nome??""}`
    });
  };
  const renderIndiceRelatorio=el=>{
    procPreencherSelect(el,indices,{
      placeholder:null,
      valueFrom:(item)=>item?.id??"",
      labelFrom:(item)=>item?.id===255?"Moeda corrente":`${item?.sigla??""} - ${item?.nome??""}`
    });
  };
  if(sysOptCfg.cboFinIndicePadrao)renderIndice(sysOptCfg.cboFinIndicePadrao);
  if(sysOptCfg.cboFinIndiceRelatorio)renderIndiceRelatorio(sysOptCfg.cboFinIndiceRelatorio);

  if(sysOptCfg.cboFinTipoCobranca){
    procPreencherSelect(sysOptCfg.cboFinTipoCobranca,tiposCobranca,{placeholder:null,valueFrom:(item)=>item?.codigo??"",labelFrom:(item)=>item?.descricao??""});
  }
  if(sysOptCfg.cboFinCatOrto){
    procPreencherSelect(sysOptCfg.cboFinCatOrto,categorias,{placeholder:null,valueFrom:(item)=>item?.id??"",labelFrom:(item)=>item?.nome??""});
  }

  if(sysOptCfg.cboDataFormato){
    procPreencherSelect(sysOptCfg.cboDataFormato,formatosData,{placeholder:null,valueFrom:(item)=>item?.id??"",labelFrom:(item)=>item?.label??item?.id??""});
  }

  if(sysOptCfg.cboAvCaptura){
    procPreencherSelect(sysOptCfg.cboAvCaptura,sistemasCaptura,{placeholder:null,valueFrom:(item)=>item?.id??"",labelFrom:(item)=>item?.label??item?.id??""});
  }
  if(sysOptCfg.cboAvWord){
    procPreencherSelect(sysOptCfg.cboAvWord,versoesWord,{placeholder:null,valueFrom:(item)=>item?.id??"",labelFrom:(item)=>item?.label??item?.id??""});
  }
  if(sysOptCfg.cboAvEmail){
    procPreencherSelect(sysOptCfg.cboAvEmail,formatosEmail,{placeholder:null,valueFrom:(item)=>item?.id??"",labelFrom:(item)=>item?.label??item?.id??""});
  }
}

function sysOptSyncUI(){
  if(!sysOptCfg)return;
  sysOptRenderSelects();
  const v=sysOptCfg.values||{};
  const clinica=v.clinica||{};
  sysOptCfg.txtClinicaNome.value=String(clinica.nome||"");
  sysOptCfg.txtClinicaEndereco.value=String(clinica.endereco||"");
  sysOptCfg.txtClinicaComplemento.value=String(clinica.complemento||"");
  sysOptCfg.txtClinicaBairro.value=String(clinica.bairro||"");
  sysOptCfg.txtClinicaCidade.value=String(clinica.cidade||"");
  sysOptCfg.txtClinicaCep.value=String(clinica.cep||"");
  sysOptCfg.cboClinicaUf.value=String(clinica.uf||"");
  sysOptCfg.txtClinicaTelefones.value=String(clinica.telefones||"");
  sysOptCfg.txtClinicaCnpj.value=String(clinica.cnpj||"");
  sysOptCfg.txtClinicaIe.value=String(clinica.inscricao_estadual||"");

  const fin=v.financeiro||{};
  sysOptCfg.cboFinIndicePadrao.value=String(fin.indice_padrao_id??"255");
  if(!sysOptCfg.cboFinIndicePadrao.value&&sysOptCfg.cboFinIndicePadrao.options.length)sysOptCfg.cboFinIndicePadrao.selectedIndex=0;
  sysOptCfg.txtFinMoeda.value=String(fin.moeda_corrente||"");
  sysOptCfg.txtFinSigla.value=String(fin.sigla_moeda||"");
  sysOptCfg.txtFinPeriodo.value=String(fin.periodo_parcelamento??30);
  sysOptCfg.cboFinTipoCobranca.value=String(fin.tipo_cobranca_padrao||"");
  sysOptCfg.cboFinCatOrto.value=fin.categoria_mensalidade_ortodontia_id==null?"":String(fin.categoria_mensalidade_ortodontia_id);
  sysOptCfg.cboFinIndiceRelatorio.value=String(fin.indice_relatorios_id??"255");
  if(!sysOptCfg.cboFinIndiceRelatorio.value&&sysOptCfg.cboFinIndiceRelatorio.options.length)sysOptCfg.cboFinIndiceRelatorio.selectedIndex=0;
  sysOptCfg.chkFinIndices.checked=!!fin.pedir_indices_diariamente;
  sysOptCfg.chkFinBaixa.checked=!!fin.lancar_creditos_baixa_clinica;
  sysOptCfg.chkFinDebitos.checked=!!fin.lancar_debitos_convenio_paciente;
  sysOptCfg.chkFinCreditos.checked=!!fin.considerar_creditos_futuros_devedores;

  const seg=v.seguranca||{};
  sysOptCfg.chkSegUsuarios.checked=!!seg.ativar_controle_usuarios;
  sysOptCfg.chkSegAuditoria.checked=!!seg.ativar_auditoria;

  const data=v.data||{};
  sysOptCfg.cboDataFormato.value=String(data.formato_data||"DD/MM/AAAA");
  sysOptCfg.txtDataAtual.value=String(data.data_atual||"");
  const horaTxt=String(data.hora_atual||"");
  const partesHora=horaTxt.split(":");
  const horaHH=(partesHora[0]||"").padStart(2,"0").slice(0,2);
  const horaMM=(partesHora[1]||"").padStart(2,"0").slice(0,2);
  if(sysOptCfg.txtHoraHh)sysOptCfg.txtHoraHh.value=horaHH;
  if(sysOptCfg.txtHoraMm)sysOptCfg.txtHoraMm.value=horaMM;
  sysOptCfg.txtAno2000.value=String(data.considerar_ano_2000_menor_que??15);
  sysOptCfg.txtSemanas.value=String(data.semanas_horarios_livres??5);

  const local=v.local||{};


  const av=v.avancado||{};
  sysOptCfg.cboAvCaptura.value=String(av.sistema_captura_imagens||"EasyCapture");
  sysOptCfg.cboAvWord.value=String(av.versao_word||"Word 2000");
  sysOptCfg.cboAvEmail.value=String(av.formato_envio_email||"formatado_com_imagens");
  sysOptCfg.txtAvImagens.value=String(av.qtd_imagens_odontograma??40);
  sysOptCfg.chkAvCpf.checked=!!av.habilitar_validacao_cpf;
  sysOptCfg.chkAvDupCpf.checked=!!av.bloquear_duplicidade_cpf;
  sysOptCfg.chkAvDebug.checked=!!av.habilitar_mensagens_depuracao;
  sysOptCfg.chkAvIgnorar.checked=!!av.ignorar_copias_driver;
  sysOptCfg.chkAvSalvar.checked=!!av.salvar_arquivos_myeasy;
  sysOptCfg.chkAvAgenda.checked=!!av.atualizar_agenda_automaticamente;
  sysOptCfg.chkAvOrcamento.checked=!!av.exigir_orcamento_aprovado;
  sysOptCfg.chkAvDente3d.checked=!!av.habilitar_dente_3d;
  sysOptCfg.chkAvCep.checked=!!av.habilitar_cep_online;
  sysOptCfg.chkAvProtese.checked=!!av.enviar_somente_num_paciente_servico_protese;
}

