      moeda_corrente:String(sysOptCfg.txtFinMoeda.value||"").trim(),
      sigla_moeda:String(sysOptCfg.txtFinSigla.value||"").trim(),
      periodo_parcelamento:String(sysOptCfg.txtFinPeriodo.value||""),
