  pgen.btnFechar.addEventListener("click",()=>{pgen.panel.classList.add("hidden");workspaceEmpty.classList.remove("hidden")});
  pgen.btnNovo.addEventListener("click",()=>pgenAbrirEditor(null));
  pgen.btnEditar.addEventListener("click",()=>pgenAbrirEditor(pgenSelecionado()?.id||null));
  pgen.btnExcluir.addEventListener("click",pgenExcluirSelecionado);
  pgen.btnFases.addEventListener("click",pgenAbrirFases);
  pgen.btnMateriais.addEventListener("click",pgenAbrirMateriais);
  pgen.cboEspecialidade.addEventListener("change",pgenCarregar);
  pgen.txtPesquisar.addEventListener("input",pgenCarregar);
  pgen.tbody.addEventListener("click",ev=>{const tr=ev.target.closest("tr[data-id]");if(!tr)return;pgenSelecionar(Number(tr.dataset.id||0))});
  pgen.tbody.addEventListener("dblclick",()=>pgenAbrirEditor(pgenSelecionado()?.id||null));
  pgen.tabPrincipal.addEventListener("click",()=>pgenSetTab("principal"));
  pgen.tabCustos.addEventListener("click",()=>pgenSetTab("custos"));
  pgen.tabVinculos.addEventListener("click",()=>pgenSetTab("vinculos"));
  pgen.editorSimbolo.addEventListener("change",pgenAtualizarPreviewSimbolo);
  pgen.cdTempoInput.addEventListener("input",()=>{if(!pgenEditorState)return;pgenEditorState.tempo=Math.max(0,Number(pgen.cdTempoInput.value||0));pgenCalcularCustos()});
  pgen.cdProteticoInput.addEventListener("input",()=>{if(!pgenEditorState)return;pgenEditorState.custo_lab=Math.max(0,Number(procParse(pgen.cdProteticoInput.value||"0")||0));pgenCalcularCustos()});
  pgen.cdProteticoInput.addEventListener("blur",()=>{if(!pgenEditorState)return;pgen.cdProteticoInput.value=procFmtBr(pgenEditorState.custo_lab||0)});
  pgen.editorCancelar.addEventListener("click",pgenFecharEditor);
  pgen.editorGravar.addEventListener("click",pgenSalvarEditor);
  pgen.editorClose.addEventListener("click",pgenFecharEditor);
  pgen.editorBackdrop.addEventListener("click",ev=>{if(ev.target===pgen.editorBackdrop)pgenFecharEditor()});
  pgen.editorHead.addEventListener("mousedown",pgenIniciarArrasteEditor);
  pgen.fasesClose.addEventListener("click",pgenFasesFechar);
  pgen.fasesBtnFechar.addEventListener("click",pgenFasesFechar);
  pgen.fasesBtnNovo.addEventListener("click",()=>pgenFaseEditAbrir(null));
