  pgen.matsClose.addEventListener("click",pgenMateriaisFechar);
  pgen.matsBtnFechar.addEventListener("click",pgenMateriaisFechar);
  pgen.matsBtnNovo.addEventListener("click",()=>pgenMaterialEditAbrir(null));
  pgen.matsBtnEditar.addEventListener("click",()=>pgenMaterialEditAbrir(pgenMaterialSelecionadoIdx));
  pgen.matsBtnExcluir.addEventListener("click",pgenMaterialExcluirSelecionado);
  pgen.matsBackdrop.addEventListener("click",ev=>{if(ev.target===pgen.matsBackdrop)pgenMateriaisFechar()});
  pgen.matsListTbody.addEventListener("click",ev=>{const tr=ev.target.closest("tr[data-idx]");if(!tr)return;pgenMateriaisSelecionar(Number(tr.dataset.idx||-1))});
  pgen.matsListTbody.addEventListener("dblclick",ev=>{const tr=ev.target.closest("tr[data-idx]");if(!tr)return;pgenMaterialEditAbrir(Number(tr.dataset.idx||-1))});
  pgen.matEditClose.addEventListener("click",pgenMaterialEditFechar);
  pgen.matEditCancelar.addEventListener("click",pgenMaterialEditFechar);
