async function pgenFaseEditAbrir(idx=null){
  if(!pgenFasesState){await pgenAbrirFases();if(!pgenFasesState)return}
  const fasesAux=await pgenCarregarAuxFases();
  procPreencherSelect(pgen.faseSelect,fasesAux,{valueFrom:item=>item?.codigo??"",labelFrom:item=>item?.nome??item?.descricao??item?.codigo??""});
  const faseAtual=(idx!=null&&idx>=0)?(pgenFasesState.fases||[])[idx]:null;
  pgenFaseEditIdx=faseAtual?idx:null;
  pgen.faseEditTitle.textContent=faseAtual?"Altera fase":"Nova fase";
  if(faseAtual){
    procGarantirOpcaoSelect(pgen.faseSelect,faseAtual.codigo,faseAtual.descricao||faseAtual.codigo);
    pgen.faseSelect.value=String(faseAtual.codigo||"");
    pgen.faseTempo.value=String(Number(faseAtual.tempo||0));
  }else{
    pgen.faseSelect.value=String(fasesAux[0]?.codigo||"");
    pgen.faseTempo.value="0";
  }
  pgen.faseEditBackdrop.classList.remove("hidden");
}
async function pgenFaseEditSalvar(){
  if(!pgenFasesState)return;
  const codigo=String(pgen.faseSelect.value||"").trim();
  if(!codigo){window.alert("Selecione a fase do procedimento.");return}
  const fasesAux=Array.isArray(pgenFasesAuxCache)?pgenFasesAuxCache:[];
  const faseAux=fasesAux.find(item=>String(item.codigo||"").trim()===codigo)||null;
  const descricao=String(faseAux?.nome||faseAux?.descricao||codigo).trim();
  const tempo=Math.max(0,Number(pgen.faseTempo.value||0));
  const fases=Array.isArray(pgenFasesState.fases)?[...pgenFasesState.fases]:[];
  const duplicada=fases.some((item,idx)=>String(item.codigo||"").trim()===codigo&&idx!==pgenFaseEditIdx);
  if(duplicada){window.alert("Esta fase jÃ¡ estÃ¡ vinculada ao procedimento.");return}
  const novaFase={codigo,descricao,tempo,sequencia:1};
  if(pgenFaseEditIdx!=null&&pgenFaseEditIdx>=0&&pgenFaseEditIdx<fases.length){
    fases[pgenFaseEditIdx]={...fases[pgenFaseEditIdx],...novaFase};
  }else{
    fases.push(novaFase);
  }
  pgenFasesState.fases=fases.map((item,idx)=>({...item,sequencia:idx+1}));
  try{
    const salvo=await pgenPersistirFases(pgenFasesState);
    pgenFasesState=pgenDetalheParaEstado(salvo);
    pgenFasesSelecionadaIdx=pgenFaseEditIdx!=null&&pgenFaseEditIdx>=0?Math.min(pgenFaseEditIdx,pgenFasesState.fases.length-1):Math.max(0,pgenFasesState.fases.length-1);
    pgenFaseEditFechar();
    pgenFasesRender();
    await pgenCarregar();
    if(pgenFasesState?.id)pgenSelecionar(pgenFasesState.id);
    if(pgenEditorId&&pgenEditorState&&Number(pgenEditorId)===Number(pgenFasesState.id||0)){
      pgenEditorState.fases=[...(pgenFasesState.fases||[])];
      pgenCalcularCustos();
    }
  }catch(err){
    window.alert(err?.message||"Falha ao gravar a fase.");
  }
}
async function pgenFaseExcluirSelecionada(){
  if(!pgenFasesState){window.alert("Selecione um procedimento genÃ©rico.");return}
  if(!(pgenFasesSelecionadaIdx>=0)){window.alert("Selecione uma fase.");return}
  const fase=(pgenFasesState.fases||[])[pgenFasesSelecionadaIdx];
  if(!fase)return;
  if(!window.confirm(`Confirma a eliminaÃ§Ã£o da fase ${fase.descricao}?`))return;
  pgenFasesState.fases=(pgenFasesState.fases||[]).filter((_,idx)=>idx!==pgenFasesSelecionadaIdx).map((item,idx)=>({...item,sequencia:idx+1}));
  try{
    const salvo=await pgenPersistirFases(pgenFasesState);
    pgenFasesState=pgenDetalheParaEstado(salvo);
    pgenFasesSelecionadaIdx=(pgenFasesState.fases||[]).length?Math.min(pgenFasesSelecionadaIdx,pgenFasesState.fases.length-1):-1;
    pgenFasesRender();
    await pgenCarregar();
    if(pgenFasesState?.id)pgenSelecionar(pgenFasesState.id);
    if(pgenEditorId&&pgenEditorState&&Number(pgenEditorId)===Number(pgenFasesState.id||0)){
      pgenEditorState.fases=[...(pgenFasesState.fases||[])];
      pgenCalcularCustos();
    }
  }catch(err){
    window.alert(err?.message||"Falha ao excluir a fase.");
  }
}
