async function pgenBuscarMateriais(){
  if(!pgen)return;
  const listaId=Number(pgen.matLista?.value||0);
  if(!listaId){
    pgenEditorBuscaMateriais=[];
    if(pgen.matSelect)pgen.matSelect.innerHTML="";
    pgenAtualizarCustoMaterialEditor();
    return;
  }
  const q=encodeURIComponent(String(pgen.matQ?.value||"").trim());
  const {res,data}=await requestJson("GET",`/materiais?lista_id=${listaId}&q=${q}&classificacao=__todos__`,undefined,true);
  pgenEditorBuscaMateriais=res&&Array.isArray(data)?data:[];
  if(pgen.matSelect){
    pgen.matSelect.innerHTML=pgenEditorBuscaMateriais.map(item=>`<option value="${item.id}">${esc(item.nome||"")}</option>`).join("");
  }
  pgenAtualizarCustoMaterialEditor();
}
function pgenAtualizarCustoMaterialEditor(){
  if(!pgen)return;
  const item=pgenEditorBuscaMateriais.find(x=>Number(x.id||0)===Number(pgen.matSelect?.value||0));
  const qtd=Math.max(0,Number(pgen.matQuantidade?.value||0));
  const custoUnit=Number(item?.custo||0);
  const total=item?(Number(item.custo||0)*qtd):0;
  if(pgen.matCustoUnit)pgen.matCustoUnit.value=procFmtBr(custoUnit);
  if(pgen.matCustoTotal)pgen.matCustoTotal.value=procFmtBr(total);
}
