  if(!res.ok){window.alert(data.detail||"Falha ao carregar os materiais do procedimento.");return}
  pgenEditorState=pgenDetalheParaEstado(data);
  pgenMaterialSelecionadoIdx=(pgenEditorState.materiais||[]).length?0:-1;
