  if(ficha.palavraChave2)ficha.palavraChave2.selectedIndex=0;
  if(ficha.palavraChave3)ficha.palavraChave3.selectedIndex=0;
  if(ficha.palavraChave4)ficha.palavraChave4.selectedIndex=0;
  if(ficha.tipoIndicacao)ficha.tipoIndicacao.selectedIndex=0;
  fichaSelecionarOpcaoPorTexto(ficha.tipoFone1,["Residencial"])||(ficha.tipoFone1&&(ficha.tipoFone1.selectedIndex=0));
  fichaSelecionarOpcaoPorTexto(ficha.tipoFone2,["Comercial"])||(ficha.tipoFone2&&(ficha.tipoFone2.selectedIndex=0));
  fichaSelecionarOpcaoPorTexto(ficha.tipoFone3,["Celular"])||(ficha.tipoFone3&&(ficha.tipoFone3.selectedIndex=0));
  fichaSelecionarOpcaoPorTexto(ficha.tipoFone4,["Recado"])||(ficha.tipoFone4&&(ficha.tipoFone4.selectedIndex=0));
  const correspondencia=document.getElementById("ficha-correspondencia");
  if(correspondencia&&correspondencia.options.length)correspondencia.selectedIndex=0;
  fichaSelecionarOpcaoPorTexto(ficha.cidade,["SÃ£o JosÃ© do Rio Preto","Sao Jose do Rio Preto"]);
  fichaSelecionarOpcaoPorTexto(ficha.cidTra,["SÃ£o JosÃ© do Rio Preto","Sao Jose do Rio Preto"]);
  if(ficha.uf)fichaSetUfOptions(ficha.uf,"SP");
  if(ficha.estTra)fichaSetUfOptions(ficha.estTra,"SP");
  if(ficha.convenio){
    if(!fichaSelecionarOpcaoPorTexto(ficha.convenio,["Particular"]))fichaEnsureSelectOption(ficha.convenio,"Particular","Particular");
    fichaAtualizarPlanosFiltro(ficha.convenio.value||"");
  }
  if(ficha.plano&&!fichaSelecionarOpcaoPorTexto(ficha.plano,["Principal"]))fichaEnsureSelectOption(ficha.plano,"Principal","Principal");
  if(ficha.tabela&&!fichaSelecionarOpcaoPorTexto(ficha.tabela,["PARTICULAR","Particular"]))fichaEnsureSelectOption(ficha.tabela,"PARTICULAR","PARTICULAR");
  fichaFotoAplicar("","");
  if(ficha.proximoRetorno)ficha.proximoRetorno.value="?";
  if(ficha.inclusao)ficha.inclusao.value=hojeBr;
  if(ficha.alteracao)ficha.alteracao.value=hojeBr;
  ficha.anamneseList.innerHTML="<tr><td>Alergia a algum medicamento?</td></tr><tr><td>Faz uso continuo de medicamentos?</td></tr><tr><td>Ja realizou cirurgia recentemente?</td></tr><tr><td>Possui doenca sistemica diagnosticada?</td></tr>";
  ficha.anamneseResposta.value="";
