  hideAllPanels();
  ficha.panel.classList.remove("hidden");
  workspaceEmpty.classList.add("hidden");
  ficha.titulo.textContent="Ficha pessoal -";
  await fichaCarregarCombos();
  await fichaLimparNovo();
