const CONVPLAN_LOGRADOUROS_V2=[{id:"",nome:""},{id:"1",nome:"Rua"},{id:"2",nome:"Avenida"},{id:"3",nome:"Alameda"},{id:"4",nome:"PraÃ§a"},{id:"5",nome:"Travessa"},{id:"6",nome:"Rodovia"},{id:"7",nome:"Outro"}];
const CONVPLAN_TIPOS_FONE_V2=[{id:"",nome:""},{id:"1",nome:"Comercial 1"},{id:"2",nome:"Comercial 2"},{id:"3",nome:"Comercial 3"},{id:"4",nome:"Fax"}];
const CONVPLAN_MODALIDADE_FAT_V2=[{id:"1",nome:"Parcial"},{id:"2",nome:"Total"}];
async function convPlanCarregarAuxConvenioV2(item=null){
  const m=convPlanCfg?.convenioModal;
  if(!m)return;
  const [logradouros,tiposContato,bairros,cidades]=await Promise.all([
    materiaisCarregarAuxTipo("Tipos de logradouro"),
    materiaisCarregarAuxTipo("Tipos de contato"),
    materiaisCarregarAuxTipo("Bairro"),
    materiaisCarregarAuxTipo("Cidade"),
  ]);
  const logOpts=(Array.isArray(logradouros)&&logradouros.length?logradouros:CONVPLAN_LOGRADOUROS_V2.map(x=>x.nome).filter(Boolean)).map((nome,idx)=>({id:String(idx+1),nome:String(nome||"")}));
  const foneOpts=(Array.isArray(tiposContato)&&tiposContato.length?tiposContato:CONVPLAN_TIPOS_FONE_V2.map(x=>x.nome).filter(Boolean)).map((nome,idx)=>({id:String(idx+1),nome:String(nome||"")}));
  convPlanSetObjectOptionsV2(m.tipolog,logOpts,"");
  [m.tipo1,m.tipo2,m.tipo3,m.tipo4].forEach(selectEl=>convPlanSetObjectOptionsV2(selectEl,foneOpts,""));
  convPlanSetObjectOptionsV2(m.bairro,(Array.isArray(bairros)?bairros:[]).map(nome=>({id:String(nome||""),nome:String(nome||"")})),"");
  convPlanSetObjectOptionsV2(m.cidade,(Array.isArray(cidades)?cidades:[]).map(nome=>({id:String(nome||""),nome:String(nome||"")})),"");
  if(item){
    m.tipolog.value=String(item?.tipo_logradouro??"");
    m.tipo1.value=String(item?.tipo_fone1??"");
    m.tipo2.value=String(item?.tipo_fone2??"");
    m.tipo3.value=String(item?.tipo_fone3??"");
    m.tipo4.value=String(item?.tipo_fone4??"");
    if(item?.bairro)convPlanSetObjectOptionsV2(m.bairro,[{id:String(item.bairro),nome:String(item.bairro)},...(Array.isArray(bairros)?bairros:[]).map(nome=>({id:String(nome||""),nome:String(nome||"")}))],"");
    if(item?.cidade)convPlanSetObjectOptionsV2(m.cidade,[{id:String(item.cidade),nome:String(item.cidade)},...(Array.isArray(cidades)?cidades:[]).map(nome=>({id:String(nome||""),nome:String(nome||"")}))],"");
    m.bairro.value=String(item?.bairro??"");
    m.cidade.value=String(item?.cidade??"");
  }
}
