function agendaContatosFiltrar(){
  const filtro=String(agendaContatos?.filtro?.value||"").trim().toLowerCase();
  const termo=String(agendaContatos?.busca?.value||"").trim().toLowerCase();
  return agendaContatosCache.filter(item=>{
    if(filtro&&String(item.tipo||"").toLowerCase()!==filtro)return false;
    if(termo&&!String(item.nome||"").toLowerCase().includes(termo))return false;
    return true;
  });
}
function agendaContatosSelecionado(){
  return agendaContatosCache.find(item=>item.id===agendaContatosSelId)||null;
}
function agendaContatosTelefonesTexto(item){
  if(!item)return"";
  const telefones=[
    [item.tel1_tipo,item.tel1],
    [item.tel2_tipo,item.tel2],
    [item.tel3_tipo,item.tel3],
    [item.tel4_tipo,item.tel4],
  ]
    .map(([tipo,fone])=>{
      const t=String(tipo||"").trim();
      const f=String(fone||"").trim();
      if(!f)return"";
      return t?`${t} ${f}`:f;
    })
    .filter(Boolean);
  return telefones.join(" / ");
}
function agendaContatosEnsureOption(selectEl,value,label){
  const alvo=String(value||"").trim();
  if(!selectEl||!alvo)return;
  const existe=[...selectEl.options].some(opt=>String(opt.value||"").trim()===alvo);
  if(existe)return;
  const opt=document.createElement("option");
  opt.value=alvo;
  opt.textContent=String(label||alvo).trim()||alvo;
  opt.dataset.legacy="true";
  selectEl.appendChild(opt);
}
function agendaContatosAtualizarFiltroTipos(){
  if(!agendaContatos)return;
  const opts=agendaContatosTiposCache.length
    ? agendaContatosTiposCache.map(item=>`<option value="${esc(item.descricao||"")}">${esc(item.descricao||"")}</option>`).join("")
    : '<option value="CirurgiÃ£o">CirurgiÃ£o</option><option value="ProtÃ©tico">ProtÃ©tico</option><option value="Fornecedor">Fornecedor</option><option value="Outros">Outros</option>';
  agendaContatos.filtro.innerHTML=`<option value=""><<Todos>></option>${opts}`;
  agendaContatos.tipo.innerHTML=opts;
}
async function agendaContatosCarregarTipos(){
  const{res,data}=await requestJson("GET","/cadastros/auxiliares?tipo=Tipos%20de%20contato",undefined,true);
  if(res.ok){
    agendaContatosTiposCache=Array.isArray(data)?data.map(item=>({descricao:item.descricao||""})):[];
  }
  agendaContatosAtualizarFiltroTipos();
}
async function agendaContatosCarregarEspecialidades(){
  if(!agendaContatos?.especialidade)return;
  const{res,data}=await requestJson("GET","/procedimentos/filtros",undefined,true);
  if(res.ok){
    agendaContatosEspecialidadesCache=Array.isArray(data?.especialidades)?data.especialidades:[];
  }
  const especialidades=agendaContatosEspecialidadesCache;
  const opts=['<option value=""></option>',...especialidades.map(item=>`<option value="${esc(String(item.codigo||""))}">${esc(String(item.nome||""))}</option>`)].join("");
  agendaContatos.especialidade.innerHTML=opts;
}
async function agendaContatosCarregarAuxiliares(){
  if(!agendaContatos)return;
  const carregar=async(tipo,select)=>{
    const{res,data}=await requestJson("GET",`/cadastros/auxiliares?tipo=${encodeURIComponent(tipo)}`,undefined,true);
    if(!res.ok||!Array.isArray(data))return;
    const opts=['<option value=""></option>',...data.map(item=>`<option value="${esc(item.descricao||"")}">${esc(item.descricao||"")}</option>`)].join("");
    select.innerHTML=opts;
  };
  if(agendaContatos.bairro)await carregar("Bairro",agendaContatos.bairro);
  if(agendaContatos.cidade)await carregar("Cidade",agendaContatos.cidade);
  if(agendaContatos.palavra1){
    const {res,data}=await requestJson("GET",`/cadastros/auxiliares?tipo=${encodeURIComponent("Palavra chave")}`,undefined,true);
    if(res.ok&&Array.isArray(data)){
      const html=['<option value=""></option>',...data.map(item=>String(item?.descricao||"").trim()).filter(Boolean).map(valor=>`<option value="${esc(valor)}">${esc(valor)}</option>`)].join("");
      agendaContatos.palavra1.innerHTML=html;
      if(agendaContatos.palavra2)agendaContatos.palavra2.innerHTML=html;
    }
  }
  const {res,data}=await requestJson("GET",`/cadastros/auxiliares?tipo=${encodeURIComponent("Tipos de contato")}`,undefined,true);
  if(res.ok&&Array.isArray(data)){
    const html=data
      .map(item=>String(item?.descricao||"").trim())
      .filter(Boolean)
      .map(item=>`<option value="${esc(item)}">${esc(item)}</option>`)
      .join("");
    [
      agendaContatos.telTipo1,
      agendaContatos.telTipo2,
      agendaContatos.telTipo3,
      agendaContatos.telTipo4,
    ].forEach(select=>{
      if(select)select.innerHTML=html;
    });
  }
}
async function agendaContatosCarregar(){
  const{res,data}=await requestJson("GET","/agenda-contatos",undefined,true);
  if(!res.ok){
    footerMsg.textContent=data.detail||"Falha ao carregar contatos.";
    return;
  }
  agendaContatosCache=Array.isArray(data)?data:[];
  agendaContatosSelId=agendaContatosCache.some(item=>item.id===agendaContatosSelId)?agendaContatosSelId:(agendaContatosCache[0]?.id||null);
  agendaContatosRender();
}

function agendaContatosRender(){
  if(!agendaContatos)return;
  const itens=agendaContatosFiltrar();
  agendaContatos.tbody.innerHTML=itens.map(item=>`<tr data-id="${item.id}" class="${item.id===agendaContatosSelId?"selected":""}"><td>${esc(item.nome||"")}</td><td>${esc(item.tipo||"")}</td><td>${esc(agendaContatosTelefonesTexto(item))}</td></tr>`).join("")||'<tr><td colspan="3"></td></tr>';
  agendaContatos.total.textContent=`${itens.length} contatos`;
}

function agendaContatosSetTab(tab){
  if(!agendaContatos)return;
  const principal=tab!=="detalhes";
  agendaContatos.tabPrincipal.classList.toggle("active",principal);
  agendaContatos.tabDetalhes.classList.toggle("active",!principal);
  agendaContatos.panePrincipal.classList.toggle("hidden",!principal);
  agendaContatos.paneDetalhes.classList.toggle("hidden",principal);
  agendaContatos.panePrincipal.style.display=principal?"block":"none";
  agendaContatos.paneDetalhes.style.display=principal?"none":"block";
}

function agendaContatosPreencherModal(item){
  if(!agendaContatos)return;
  agendaContatos.nome.value=item?.nome||"";
  agendaContatos.tipo.value=item?.tipo||agendaContatos.tipo.value||"";
  agendaContatos.contato.value=item?.contato||"";
  agendaContatos.anivDia.value=item?.aniversario_dia?String(item.aniversario_dia):"";
  agendaContatos.anivMes.value=item?.aniversario_mes?String(item.aniversario_mes):"";
  agendaContatos.endereco.value=item?.endereco||"";
  agendaContatos.complemento.value=item?.complemento||"";
  if(agendaContatos.bairro){
    const valorBairro=String(item?.bairro||"").trim();
    if(valorBairro)agendaContatosEnsureOption(agendaContatos.bairro,valorBairro,valorBairro);
    agendaContatos.bairro.value=valorBairro;
  }
  if(agendaContatos.cidade){
    const valorCidade=String(item?.cidade||"").trim();
    if(valorCidade)agendaContatosEnsureOption(agendaContatos.cidade,valorCidade,valorCidade);
    agendaContatos.cidade.value=valorCidade;
  }
  agendaContatos.cep.value=item?.cep||"";
  agendaContatos.uf.value=(item?.uf||"").toUpperCase();
  agendaContatos.pais.value=item?.pais||"";
  agendaContatos.telTipo1.value=item?.tel1_tipo||agendaContatos.telTipo1.value||"";
  agendaContatos.tel1.value=item?.tel1||"";
  agendaContatos.telTipo2.value=item?.tel2_tipo||agendaContatos.telTipo2.value||"";
  agendaContatos.tel2.value=item?.tel2||"";
  agendaContatos.telTipo3.value=item?.tel3_tipo||agendaContatos.telTipo3.value||"";
  agendaContatos.tel3.value=item?.tel3||"";
  agendaContatos.telTipo4.value=item?.tel4_tipo||agendaContatos.telTipo4.value||"";
  agendaContatos.tel4.value=item?.tel4||"";
  agendaContatos.email.value=item?.email||"";
  agendaContatos.homepage.value=item?.homepage||"";
  if(agendaContatos.palavra1){
    const valor1=String(item?.palavra_chave_1||"").trim();
    if(valor1)agendaContatosEnsureOption(agendaContatos.palavra1,valor1,valor1);
    agendaContatos.palavra1.value=valor1;
  }
  if(agendaContatos.palavra2){
    const valor2=String(item?.palavra_chave_2||"").trim();
    if(valor2)agendaContatosEnsureOption(agendaContatos.palavra2,valor2,valor2);
    agendaContatos.palavra2.value=valor2;
  }
  if(agendaContatos.registro)agendaContatos.registro.value=item?.registro||"";
  if(agendaContatos.especialidade){
    const valorEsp=String(item?.especialidade||"").trim();
    if(valorEsp)agendaContatosEnsureOption(agendaContatos.especialidade,valorEsp,valorEsp);
    agendaContatos.especialidade.value=valorEsp;
  }
  agendaContatos.diretas.checked=!!item?.incluir_malas_diretas;
  agendaContatos.preferidos.checked=!!item?.incluir_preferidos;
  agendaContatos.observacoes.value=item?.observacoes||"";
}
function agendaContatosAbrirModal(modo){
  if(!agendaContatos)return;
  const editar=modo==="editar";
  agendaContatos.modalTitle.textContent=editar?"Alterar contato":"Novo contato";
  if(agendaContatos.modalElimina)agendaContatos.modalElimina.disabled=!editar;
  const item=editar?agendaContatosSelecionado():null;
  agendaContatos.modalBackdrop.dataset.editId=editar&&item?String(item.id):"";
  agendaContatosGarantirAbaDetalhes();
  agendaContatosPreencherModal(item);
  agendaContatosSetTab("principal");
  agendaContatos.modalBackdrop.classList.remove("hidden");
}

function agendaContatosFecharModal(){
  if(!agendaContatos)return;
  agendaContatos.modalBackdrop.classList.add("hidden");
}
function agendaContatosMontarPayload(){
  return{
    nome:String(agendaContatos.nome.value||"").trim(),
    tipo:String(agendaContatos.tipo.value||"").trim(),
    contato:String(agendaContatos.contato.value||"").trim(),
    aniversario_dia:Number(agendaContatos.anivDia.value||0)||null,
    aniversario_mes:Number(agendaContatos.anivMes.value||0)||null,
    endereco:String(agendaContatos.endereco.value||"").trim(),
    complemento:String(agendaContatos.complemento.value||"").trim(),
    bairro:String(agendaContatos.bairro?.value||"").trim(),
    cidade:String(agendaContatos.cidade?.value||"").trim(),
    cep:String(agendaContatos.cep.value||"").trim(),
    uf:String(agendaContatos.uf.value||"").trim(),
    pais:String(agendaContatos.pais.value||"").trim(),
    tel1_tipo:String(agendaContatos.telTipo1.value||"").trim(),
    tel1:String(agendaContatos.tel1.value||"").trim(),
    tel2_tipo:String(agendaContatos.telTipo2.value||"").trim(),
    tel2:String(agendaContatos.tel2.value||"").trim(),
    tel3_tipo:String(agendaContatos.telTipo3.value||"").trim(),
    tel3:String(agendaContatos.tel3.value||"").trim(),
    tel4_tipo:String(agendaContatos.telTipo4.value||"").trim(),
    tel4:String(agendaContatos.tel4.value||"").trim(),
    email:String(agendaContatos.email.value||"").trim(),
    homepage:String(agendaContatos.homepage.value||"").trim(),
    palavra_chave_1:String(agendaContatos.palavra1?.value||"").trim(),
    palavra_chave_2:String(agendaContatos.palavra2?.value||"").trim(),
    registro:String(agendaContatos.registro?.value||"").trim(),
    especialidade:String(agendaContatos.especialidade?.value||"").trim(),
    incluir_malas_diretas:!!agendaContatos.diretas.checked,
    incluir_preferidos:!!agendaContatos.preferidos.checked,
    observacoes:String(agendaContatos.observacoes.value||"").trim()
  };
}
async function agendaContatosSalvarModal(){
  const payload=agendaContatosMontarPayload();
  if(!payload.nome){window.alert("Informe o nome.");return}
  const editId=Number(agendaContatos.modalBackdrop.dataset.editId||0);
  const method=editId?"PUT":"POST";
  const path=editId?`/agenda-contatos/${editId}`:"/agenda-contatos";
  const{res,data}=await requestJson(method,path,payload,true);
  if(!res.ok){window.alert(data.detail||"Falha ao salvar contato.");return}
  agendaContatosFecharModal();
  agendaContatosSelId=Number(data.id||editId)||agendaContatosSelId;
  await agendaContatosCarregar();
}
async function agendaContatosExcluir(){
  const item=agendaContatosSelecionado();
  if(!item){window.alert("Selecione um contato.");return}
  if(!window.confirm(`Deseja eliminar o contato '${item.nome}'?`))return;
  const{res,data}=await requestJson("DELETE",`/agenda-contatos/${item.id}`,undefined,true);
  if(!res.ok){window.alert(data.detail||"Falha ao eliminar contato.");return}
  agendaContatosSelId=null;
  await agendaContatosCarregar();
}

function agendaContatosVincularEventos(){
  if(!agendaContatos||agendaContatos.panel.dataset.bound==="1")return;
  agendaContatos.panel.dataset.bound="1";
  agendaContatos.filtro.addEventListener("change",agendaContatosRender);
  agendaContatos.busca.addEventListener("input",agendaContatosRender);
  bindStandardGridActivation(agendaContatos.tbody,agendaContatosSelecionarLinha,()=>{const item=agendaContatosSelecionado();if(!item){window.alert("Selecione um contato.");return}agendaContatosAbrirModal("editar")});
  agendaContatos.btnNovo.addEventListener("click",()=>agendaContatosAbrirModal("novo"));
  agendaContatos.btnEditar.addEventListener("click",()=>{if(!agendaContatosSelId){window.alert("Selecione um contato.");return}agendaContatosAbrirModal("editar")});
  agendaContatos.btnExcluir.addEventListener("click",agendaContatosExcluir);
  agendaContatos.btnImprimir.addEventListener("click",()=>{footerMsg.textContent="ImpressÃ£o da agenda de contatos: em planejamento."});
  agendaContatos.btnRelatorio.addEventListener("click",()=>{footerMsg.textContent="RelatÃ³rio de contatos: em planejamento."});
  agendaContatos.btnFechar.addEventListener("click",()=>{agendaContatos.panel.classList.add("hidden");workspaceEmpty.classList.remove("hidden")});
  agendaContatos.tabPrincipal.addEventListener("click",()=>agendaContatosSetTab("principal"));
  agendaContatos.tabDetalhes.addEventListener("click",()=>{agendaContatosGarantirAbaDetalhes();agendaContatosSetTab("detalhes")});
  agendaContatos.modalElimina.addEventListener("click",async()=>{if(!agendaContatos.modalBackdrop.dataset.editId)return;agendaContatosFecharModal();await agendaContatosExcluir()});
  agendaContatos.modalCancelar.addEventListener("click",agendaContatosFecharModal);
  agendaContatos.modalOk.addEventListener("click",agendaContatosSalvarModal);
  agendaContatos.modalImprime.addEventListener("click",()=>{footerMsg.textContent="ImpressÃ£o de contato: em planejamento."});
  if(agendaContatos.modalBackdrop)agendaContatos.modalBackdrop.addEventListener("click",ev=>{if(ev.target===agendaContatos.modalBackdrop)agendaContatosFecharModal()});
}

async function agendaContatosAbrir(){
  agendaContatosEnsureUI();
  agendaContatosVincularEventos();
  hideAllPanels();
  ensurePanelChrome(agendaContatos.panel);
  agendaContatos.panel.classList.remove("hidden");
  workspaceEmpty.classList.add("hidden");
  await agendaContatosCarregarTipos();
  await agendaContatosCarregarEspecialidades();
  await agendaContatosCarregarAuxiliares();
  await agendaContatosCarregar();
  footerMsg.textContent="Agenda de contatos aberta.";
}
