function agendaLegadoFmtStamp(valor){
  if(!valor)return"";
  const d=new Date(String(valor));
  if(Number.isNaN(d.getTime()))return String(valor||"");
  const dd=String(d.getDate()).padStart(2,"0");
  const mm=String(d.getMonth()+1).padStart(2,"0");
  const yyyy=String(d.getFullYear());
  const hh=String(d.getHours()).padStart(2,"0");
  const mi=String(d.getMinutes()).padStart(2,"0");
  return `${dd}/${mm}/${yyyy} ${hh}:${mi}`;
}
function agendaLegadoNumOrNull(value){
  const n=Number(value);
  return Number.isFinite(n)?Math.trunc(n):null;
}
function agendaLegadoSetModalTab(tab){
  if(!agendaLegado)return;
  const t=tab==="repete"?"repete":"dados";
  if(agendaLegado.tabDados)agendaLegado.tabDados.classList.toggle("active",t==="dados");
  if(agendaLegado.tabRepete)agendaLegado.tabRepete.classList.toggle("active",t==="repete");
  if(agendaLegado.tabDadosPanel)agendaLegado.tabDadosPanel.classList.toggle("hidden",t!=="dados");
  if(agendaLegado.tabRepetePanel)agendaLegado.tabRepetePanel.classList.toggle("hidden",t!=="repete");
}
function agendaLegadoRenderAuxSelect(selectEl,itens,placeholder=""){
  if(!selectEl)return;
  const opts=[];
  if(placeholder)opts.push(`<option value="">${esc(placeholder)}</option>`);
  (Array.isArray(itens)?itens:[]).forEach(item=>{
    const vRaw=item?.valor_int!=null?item.valor_int:item?.codigo;
    const val=String(vRaw==null?"":vRaw).trim();
    if(!val)return;
    const desc=String(item?.descricao||item?.nome||item?.codigo||val).trim();
    opts.push(`<option value="${esc(val)}">${esc(desc)}</option>`);
  });
  selectEl.innerHTML=opts.join("");
}
