function agendaSemanaRenderEstrutura(){
  if(!agendaSemana)return;
  agendaSemanaAtualizarSlots();
  const sbWidth=Math.max(0,Number((agendaSemana.scroll?.offsetWidth||0)-(agendaSemana.scroll?.clientWidth||0))||0);
  if(agendaSemana.panel)agendaSemana.panel.style.setProperty("--agenda-scrollbar",`${sbWidth}px`);
  const slotHeight=AGENDA_SEMANA_SLOT_HEIGHT;
  const height=agendaSemanaSlots.length*slotHeight;
  if(agendaSemana.panel)agendaSemana.panel.style.setProperty("--slot-height",`${slotHeight}px`);
  agendaSemana.timeCol.innerHTML=agendaSemanaSlots.map(slot=>`<div class="agenda-semana-time">${slot.label}</div>`).join("");
  agendaSemana.timeCol.style.height=`${height}px`;
  const foco=agendaSemanaState.focusDate||new Date();
  if(!agendaSemanaState.weekStart)agendaSemanaState.weekStart=agendaSemanaStartOfWeek(foco);
  const weekStart=agendaSemanaState.weekStart;
  const days=AGENDA_SEMANA_DIAS.map((dia,idx)=>agendaSemanaAddDays(weekStart,idx));
  agendaSemanaState.weekDates=days;
  agendaSemana.headDays.innerHTML=days.map((d,idx)=>`<div class="agenda-semana-day-head">${AGENDA_SEMANA_DIAS[idx].short} - ${agendaSemanaFormatDateBr(d)}</div>`).join("");
  agendaSemana.daysWrap.innerHTML=days.map((_,idx)=>`<div class="agenda-semana-day" data-day="${idx}"></div>`).join("");
  [...agendaSemana.daysWrap.children].forEach((col,idx)=>{
    col.style.height=`${height}px`;
    col.ondblclick=ev=>{
      if(ev.target.closest(".agenda-semana-event"))return;
      const rect=col.getBoundingClientRect();
      const slotIdx=Math.max(0,Math.min(agendaSemanaSlots.length-1,Math.floor((ev.clientY-rect.top)/slotHeight)));
      const slot=agendaSemanaSlots[slotIdx];
      if(!slot)return;
      const dataRef=days[idx];
      const dataIso=agendaSemanaToIsoDate(dataRef);
      const hora=agendaSemanaMinToHHMM(slot.min);
      agendaSemanaAbrirModalNovo(dataIso,hora);
    };
  });
  const sbWidthFinal=Math.max(0,Number((agendaSemana.scroll?.offsetWidth||0)-(agendaSemana.scroll?.clientWidth||0))||0);
  if(agendaSemana.panel)agendaSemana.panel.style.setProperty("--agenda-scrollbar",`${sbWidthFinal}px`);
  agendaSemanaAtualizarTabs();
}
function agendaSemanaEventoTipo(item){
  const tipo=Number(item?.tipo);
  if(Number.isFinite(tipo)){
    if(tipo===1)return"particular";
    if(tipo===2)return"convenio";
  }
  const motivo=String(item?.motivo||"").toLowerCase();
  if(motivo.includes("convÃªnio")||motivo.includes("convenio"))return"convenio";
  if(motivo.includes("compromisso")||motivo.includes("bloqueio"))return"compromisso";
  return"compromisso";
}
function agendaSemanaCorEvento(item,cfg){
  const tipo=agendaSemanaEventoTipo(item);
  if(tipo==="particular")return cfg.apresentacao_particular_cor||"#ffff00";
  if(tipo==="convenio")return cfg.apresentacao_convenio_cor||"#0000ff";
  return cfg.apresentacao_compromisso_cor||"#00e5ef";
}
function agendaSemanaFontStyle(cfg){
  const f=cfg.apresentacao_fonte||{};
  const weight=f.bold?"700":"400";
  const style=f.italic?"italic":"normal";
  const deco=[f.underline?"underline":"",f.strike?"line-through":""].filter(Boolean).join(" ")||"none";
  const size=Math.max(6,Number(f.size||8)||8);
  return`font-family:${f.family||"MS Sans Serif"};font-size:${size}px;font-weight:${weight};font-style:${style};text-decoration:${deco};color:${f.color||"#000000"}`;
}
function agendaSemanaEventoTexto(item,cfg){
  const campos=Array.isArray(cfg.visualizacao_campos)?cfg.visualizacao_campos:[];
  const valores=[];
  const pushValor=(v)=>{const t=String(v||"").trim();if(t)valores.push(t)};
  campos.forEach(campo=>{
    switch(campo){
      case "NÃºmero do paciente":pushValor(item?.nro_pac);break;
      case "NÃºmero do prontuÃ¡rio":pushValor(item?.nro_pac);break;
      case "Nome do paciente":pushValor(item?.nome);break;
      case "MatrÃ­cula":pushValor(item?.nro_pac);break;
      case "ConvÃªnio":pushValor(item?.convenio);break;
      case "Tabela":pushValor(item?.tabela);break;
      case "Fone 1":pushValor(item?.fone1);break;
      case "Fone 2":pushValor(item?.fone2);break;
      case "Fone 3":pushValor(item?.fone3);break;
      case "Sala":if(item?.sala!=null)pushValor(`Sala: ${item.sala}`);break;
      default:break;
    }
  });
  if(!valores.length){
    pushValor(item?.nome||item?.motivo||"");
  }
  const hora=agendaLegadoFmtHora(item?.hora_inicio||0);
  let linha1=hora;
  if(valores.length){
    linha1=hora?`${hora} - ${valores.shift()}`:valores.shift();
  }
  const linhas=[linha1,...valores];
  return linhas.filter(Boolean).join("\n");
}
function agendaSemanaAdicionarBloqueios(eventos,cfg){
  const bloqueios=Array.isArray(cfg.bloqueios_itens)?cfg.bloqueios_itens:[];
  if(!bloqueios.length)return eventos;
  const diasSemana=agendaSemanaState.weekDates||[];
  const novos=[...eventos];
  bloqueios.forEach(b=>{
    const diaSem=Number(b?.dia_sem||0)||0;
    if(diaSem<1||diaSem>7)return;
    diasSemana.forEach((d,idx)=>{
      if(idx!==diaSem-1)return;
      const dataBr=agendaSemanaFormatDateBr(d,true);
      const vigIni=String(b?.vigencia_inicio||b?.data_ini||"").trim();
      const vigFim=String(b?.vigencia_fim||b?.data_fin||"").trim();
      if(vigIni){
        const [di,mi,ai]=vigIni.split("/").map(Number);
        if(di&&mi&&ai){
          const ini=new Date(ai,mi-1,di);
          if(d<ini)return;
        }
      }
      if(vigFim){
        const [df,mf,af]=vigFim.split("/").map(Number);
        if(df&&mf&&af){
          const fim=new Date(af,mf-1,df);
          if(d>fim)return;
        }
      }
      novos.push({id:`bloq-${idx}-${b.id||b.msg_agenda||b.mensagem||""}`,data:d.toISOString().slice(0,10),hora_inicio:agendaLegadoParseHora(b?.hora_ini||b?.inicio||"")||0,hora_fim:agendaLegadoParseHora(b?.hora_fin||b?.final||"")||0,nome:String(b?.msg_agenda||b?.mensagem||"Bloqueio"),motivo:String(b?.msg_agenda||b?.mensagem||"Bloqueio"),tipo:null,fone1:"",fone2:"",fone3:"",sala:""});
    });
  });
  return novos;
}
function agendaSemanaRenderEventos(){
  if(!agendaSemana)return;
  const cfg=agendaSemanaState.config||agendaSemanaConfigPadrao();
  const startMin=agendaSemanaState.startMin||420;
  const endMin=agendaSemanaState.endMin||1200;
  const step=agendaSemanaState.step||5;
  const slotHeight=AGENDA_SEMANA_SLOT_HEIGHT;
  const cols=[...agendaSemana.daysWrap.children];
  cols.forEach(col=>col.innerHTML="");
  let eventos=Array.isArray(agendaSemanaCache)?agendaSemanaCache:[];
  const esp=String(agendaSemana.selectEspecialidade?.value||"").trim();
  const prestSel=Number(agendaSemana.selectPrestador?.value||0)||0;
  if(esp&&!prestSel){
    const permitidos=new Set(agendaSemanaPrestadoresFiltrados().map(item=>Number(item.id||0)));
    eventos=eventos.filter(item=>permitidos.has(Number(item.id_prestador||0)));
  }
  eventos=agendaSemanaAdicionarBloqueios(eventos,cfg);
  eventos.forEach(item=>{
    const dataStr=String(item?.data||"").trim();
    if(!dataStr)return;
    const d=new Date(dataStr);
    if(Number.isNaN(d.getTime()))return;
    const idx=agendaSemanaDayIndex(d);
    if(idx<0||idx>5)return;
    const col=cols[idx];
    if(!col)return;
    const inicioMin=Math.floor((Number(item.hora_inicio||0)||0)/60000);
    let fimMin=Math.floor((Number(item.hora_fim||0)||0)/60000);
    if(!fimMin||fimMin<=inicioMin)fimMin=inicioMin+step;
    const topMin=Math.max(startMin,inicioMin);
    const endMinReal=Math.min(endMin,fimMin);
    if(endMinReal<=topMin)return;
    const top=((topMin-startMin)/step)*slotHeight;
    const height=Math.max(slotHeight,(endMinReal-topMin)/step*slotHeight);
    const bg=agendaSemanaCorEvento(item,cfg);
    const fontStyle=agendaSemanaFontStyle(cfg);
    const texto=agendaSemanaEventoTexto(item,cfg);
    col.insertAdjacentHTML("beforeend",`<div class="agenda-semana-event" style="top:${top}px;height:${height}px;background:${bg};${fontStyle}">${esc(texto)}</div>`);
  });
}
async function agendaSemanaCarregarEventos(){
  const start=agendaSemanaState.weekStart||agendaSemanaStartOfWeek(new Date());
  const end=agendaSemanaAddDays(start,5);
  const params=new URLSearchParams();
  params.set("start",start.toISOString().slice(0,10));
  params.set("end",end.toISOString().slice(0,10));
  const prestador=String(agendaSemana.selectPrestador?.value||"").trim();
  const unidade=String(agendaSemana.selectUnidade?.value||"").trim();
  if(prestador)params.set("prestador_id",prestador);
  if(unidade)params.set("unidade_id",unidade);
  params.set("limit","5000");
  const{res,data}=await requestJson("GET",`/agenda-legado?${params.toString()}`,undefined,true);
  if(!res.ok){
    footerMsg.textContent=data?.detail||"Falha ao carregar agenda da semana.";
    agendaSemanaCache=[];
    agendaSemanaRenderEventos();
    return;
  }
  agendaSemanaCache=Array.isArray(data)?data:[];
  agendaSemanaRenderEventos();
}
function agendaSemanaAtualizarSemana(deltaDias){
  agendaSemanaState.weekStart=agendaSemanaAddDays(agendaSemanaState.weekStart||agendaSemanaStartOfWeek(new Date()),deltaDias);
  agendaSemanaRenderEstrutura();
  agendaSemanaCarregarEventos();
}
function agendaSemanaVincularEventos(){
  if(!agendaSemana||agendaSemana.panel.dataset.bound==="1")return;
  agendaSemana.panel.dataset.bound="1";
  agendaSemana.btnFechar.addEventListener("click",()=>{agendaSemana.panel.classList.add("hidden");workspaceEmpty.classList.remove("hidden")});
  agendaSemana.mesPrev.addEventListener("click",()=>agendaSemanaShiftMonths(-1));
  agendaSemana.mesNext.addEventListener("click",()=>agendaSemanaShiftMonths(1));
  agendaSemana.semanaPrev.addEventListener("click",()=>agendaSemanaShiftDays(-7));
  agendaSemana.semanaNext.addEventListener("click",()=>agendaSemanaShiftDays(7));
  agendaSemana.diaPrev.addEventListener("click",()=>agendaSemanaShiftDays(-1));
  agendaSemana.diaNext.addEventListener("click",()=>agendaSemanaShiftDays(1));
  agendaSemana.btnCal.addEventListener("click",ev=>{ev.stopPropagation();if(agendaSemana.cal.classList.contains("hidden")){agendaSemanaCalendarioAbrir()}else{agendaSemanaCalendarioFechar()}});
  agendaSemana.btnPaciente.addEventListener("click",()=>{footerMsg.textContent="Paciente: em planejamento."});
  agendaSemana.btnHorario.addEventListener("click",()=>{footerMsg.textContent="HorÃ¡rio: em planejamento."});
  agendaSemana.btnImprimir.addEventListener("click",()=>{footerMsg.textContent="ImpressÃ£o da agenda: em planejamento."});
  agendaSemana.btnAviso.addEventListener("click",()=>{footerMsg.textContent="Envio de aviso: em planejamento."});
  agendaSemana.btnPublicar.addEventListener("click",()=>{footerMsg.textContent="PublicaÃ§Ã£o da agenda no MyEasy: em planejamento."});
  agendaSemana.btnConfig.addEventListener("click",()=>{if(typeof prestAgendaAbrir==="function"){prestAgendaAbrir();return}footerMsg.textContent="ConfiguraÃ§Ã£o de agenda: em planejamento."});
  agendaSemana.tabDia.addEventListener("click",()=>{agendaSemanaTabAtivar("dia");footerMsg.textContent="Agenda do dia: em planejamento."});
  agendaSemana.tabSemana.addEventListener("click",()=>{agendaSemanaTabAtivar("semana")});
  agendaSemana.tabClinica.addEventListener("click",()=>{agendaSemanaTabAtivar("clinica");footerMsg.textContent="Agenda da cl\u00ednica: em planejamento."});
  agendaSemana.selectEspecialidade.addEventListener("change",()=>{
    agendaSemanaSaveFiltro("especialidade",String(agendaSemana.selectEspecialidade?.value||""));
    agendaSemanaPreencherPrestadores();
    agendaSemanaRenderEstrutura();
    agendaSemanaCarregarEventos();
  });
  agendaSemana.selectPrestador.addEventListener("change",()=>{
    agendaSemanaSaveFiltro("prestador_id",String(agendaSemana.selectPrestador?.value||""));
    agendaSemanaRenderEstrutura();
    agendaSemanaCarregarEventos();
  });
  agendaSemana.selectUnidade.addEventListener("change",()=>{
    agendaSemanaSaveFiltro("unidade_id",String(agendaSemana.selectUnidade?.value||""));
    agendaSemanaCarregarEventos();
  });
  agendaSemana.calPrev.addEventListener("click",ev=>{ev.stopPropagation();const base=agendaSemanaState.calDate||agendaSemanaState.focusDate||new Date();agendaSemanaState.calDate=new Date(base.getFullYear(),base.getMonth()-1,1);agendaSemanaCalendarioRender()});
  agendaSemana.calNext.addEventListener("click",ev=>{ev.stopPropagation();const base=agendaSemanaState.calDate||agendaSemanaState.focusDate||new Date();agendaSemanaState.calDate=new Date(base.getFullYear(),base.getMonth()+1,1);agendaSemanaCalendarioRender()});
  agendaSemana.calGrid.addEventListener("click",ev=>{const cell=ev.target.closest(".agenda-semana-cal-cell[data-date]");if(!cell)return;const iso=String(cell.dataset.date||"");if(!iso)return;agendaSemanaSetFocusDate(new Date(iso));agendaSemanaCalendarioFechar();agendaSemanaRenderEstrutura();agendaSemanaCarregarEventos()});
  document.addEventListener("click",ev=>{if(!agendaSemana?.cal||agendaSemana.cal.classList.contains("hidden"))return;const isInside=agendaSemana.cal.contains(ev.target)||agendaSemana.btnCal.contains(ev.target);if(!isInside)agendaSemanaCalendarioFechar()});
}
async function agendaSemanaAbrir(){
  agendaSemanaEnsureUI();
  agendaSemanaVincularEventos();
  hideAllPanels();
  ensurePanelChrome(agendaSemana.panel);
  agendaSemanaEnsureWindowControls();
  agendaSemana.panel.classList.remove("hidden");
  workspaceEmpty.classList.add("hidden");
  if(!agendaSemanaState.focusDate)agendaSemanaSetFocusDate(agendaSemanaResolveDataInicial());
  else if(!agendaSemanaState.weekStart)agendaSemanaState.weekStart=agendaSemanaStartOfWeek(agendaSemanaState.focusDate);
  await agendaSemanaCarregarPrestadores();
  await agendaSemanaCarregarUnidades();
  await agendaSemanaCarregarEspecialidades();
  agendaSemanaPreencherEspecialidades();
  agendaSemanaPreencherPrestadores();
  agendaSemanaPreencherUnidades();
  agendaSemanaTabAtivar("semana");
  agendaSemanaRenderEstrutura();
  await agendaSemanaCarregarEventos();
  footerMsg.textContent="Agenda da semana aberta.";
}
