function cidFiltrar(){
  const q=(cid?.busca?.value||"").trim().toLowerCase();
  if(!q)return cidCache||[];
  return (cidCache||[]).filter(x=>String(x.codigo||"").toLowerCase().includes(q)||String(x.descricao||"").toLowerCase().includes(q));
}
function cidRender(){
  if(!cid)return;
  const rows=cidFiltrar();
  cid.total.textContent=`${rows.length} itens`;
  cidRenderToken+=1;
  const token=cidRenderToken;
  cid.tbody.innerHTML="";
  if(!rows.length)return;
  const batchSize=400;
  let index=0;
  const renderBatch=()=>{
    if(token!==cidRenderToken||!cid?.tbody)return;
    const chunk=rows.slice(index,index+batchSize);
    if(!chunk.length)return;
    cid.tbody.insertAdjacentHTML("beforeend",chunk.map(x=>`<tr data-id="${x.id}" class="${x.id===cidSelId?"selected":""}"><td>${esc(x.codigo||"")}</td><td>${esc(x.descricao||"")}</td></tr>`).join(""));
    index+=batchSize;
    if(index<rows.length)window.requestAnimationFrame(renderBatch);
  };
  window.requestAnimationFrame(renderBatch);
}
function cidSelecionado(){
  return cidCache.find(x=>x.id===cidSelId)||null;
}
async function cidCarregar(){
  const{res,data}=await requestJson("GET","/cid",undefined,true);
  if(!res.ok){
    footerMsg.textContent=data.detail||"Falha ao carregar CID.";
    return;
  }
  cidCache=Array.isArray(data)?data:[];
  cidSelId=cidCache.some(x=>x.id===cidSelId)?cidSelId:(cidCache[0]?.id||null);
  cidRender();
}
function cidPreencherModal(item){
  if(!cid)return;
  cid.modalCodigo.value=item?.codigo||"";
  cid.modalDoenca.value=item?.descricao||"";
  cid.modalObservacoes.value=item?.observacoes||"";
  cid.modalPreferidos.checked=!!item?.preferido;
}
function cidMontarPayload(){
  return{
    codigo:String(cid.modalCodigo.value||"").trim(),
    descricao:String(cid.modalDoenca.value||"").trim(),
    observacoes:String(cid.modalObservacoes.value||"").trim(),
    preferido:!!cid.modalPreferidos.checked
  };
}
async function cidSalvarModal(){
  const payload=cidMontarPayload();
  if(!payload.codigo||!payload.descricao){window.alert("Informe cÃ³digo e doenÃ§a.");return}
  const editId=Number(cid.modalBackdrop.dataset.editId||0);
  const method=editId?"PUT":"POST";
  const path=editId?`/cid/${editId}`:"/cid";
  const{res,data}=await requestJson(method,path,payload,true);
  if(!res.ok){window.alert(data.detail||"Falha ao salvar CID.");return}
  cidFecharModal();
  cidSelId=Number(data.id||editId)||cidSelId;
  await cidCarregar();
}
async function cidExcluirSelecionado(){
  const item=cidSelecionado();
  if(!item){window.alert("Selecione uma doenÃ§a.");return}
  if(!window.confirm(`Deseja eliminar o CID '${item.codigo} - ${item.descricao}'?`))return;
  const{res,data}=await requestJson("DELETE",`/cid/${item.id}`,undefined,true);
  if(!res.ok){window.alert(data.detail||"Falha ao eliminar CID.");return}
  cidSelId=null;
  await cidCarregar();
}
function cidAbrirModal(modo){
  if(!cid)return;
  const editar=modo==="editar";
  cid.modalTitle.textContent=editar?"Alterar doenÃ§a":"Nova doenÃ§a";
  const item=editar?cidSelecionado():null;
  cid.modalBackdrop.dataset.editId=editar&&item?String(item.id):"";
  cidPreencherModal(item);
  cid.modalBackdrop.classList.remove("hidden");
}
function cidFecharModal(){
  if(!cid)return;
  cid.modalBackdrop.classList.add("hidden");
}
function cidVincularEventos(){
  if(!cid||cid.panel.dataset.bound==="1")return;
  cid.panel.dataset.bound="1";
  cid.busca.addEventListener("input",()=>{if(cidBuscaTimer)window.clearTimeout(cidBuscaTimer);cidBuscaTimer=window.setTimeout(()=>{cidSelId=null;cidRender()},120)});
  cid.tbody.addEventListener("click",ev=>{
    const tr=ev.target.closest("tr[data-id]");
    if(!tr)return;
    cidSelId=Number(tr.dataset.id||0);
    cidRender();
  });
  cid.btnNovo.addEventListener("click",()=>cidAbrirModal("novo"));
  cid.btnEditar.addEventListener("click",()=>{if(!cidSelId){window.alert("Selecione uma doenÃ§a.");return}cidAbrirModal("editar")});
  cid.btnExcluir.addEventListener("click",cidExcluirSelecionado);
  cid.btnFechar.addEventListener("click",()=>{cid.panel.classList.add("hidden");workspaceEmpty.classList.remove("hidden")});
  cid.modalCancelar.addEventListener("click",cidFecharModal);
  cid.modalOk.addEventListener("click",cidSalvarModal);
  if(cid.modalBackdrop)cid.modalBackdrop.addEventListener("click",ev=>{if(ev.target===cid.modalBackdrop)cidFecharModal()});
}
async function cidAbrir(){
  cidEnsureUI();
  cidVincularEventos();
  hideAllPanels();
  ensurePanelChrome(cid.panel);
  cid.panel.classList.remove("hidden");
  workspaceEmpty.classList.add("hidden");
  await cidCarregar();
  footerMsg.textContent="Tabela de doenÃ§as (CID) aberta.";
}
