function simbolosSelecionarLinha(tr){
  if(!simbolosCfg||!(tr instanceof HTMLElement))return;
  simbolosSelId=Number(tr.dataset.id||0)||null;
  simbolosCfg.tbody.querySelectorAll("tr.selected").forEach(row=>row.classList.remove("selected"));
  if(simbolosSelId)tr.classList.add("selected");
}
async function simbolosCarregar(){
  const{res,data}=await requestJson("GET","/cadastros/simbolos-graficos",undefined,true);
  if(!res.ok){footerMsg.textContent=data.detail||"Falha ao carregar sÃ­mbolos.";return}
  simbolosCache=Array.isArray(data)?data:[];
  simbolosSelId=simbolosCache.some(x=>x.id===simbolosSelId)?simbolosSelId:(simbolosCache[0]?.id||null);
  simbolosRender();
  simbolosRenderBiblioteca();
}
function simbolosPreencherEspecialidades(){
  if(!simbolosCfg?.modalEspecialidade)return;
  const itens=[...simbolosEspecialidadesMap.entries()].sort((a,b)=>String(a[1]).localeCompare(String(b[1])));
  simbolosCfg.modalEspecialidade.innerHTML=itens.map(([codigo,desc])=>`<option value="${esc(String(codigo))}">${esc(String(desc))}</option>`).join("");
  if(simbolosCfg.modalEspecialidade.options.length===0)simbolosCfg.modalEspecialidade.innerHTML='<option value="">Sem especialidade</option>';
}
function simbolosAbrirModal(modo){
  if(!simbolosCfg)return;
  const editar=modo==="editar";
  simbolosCfg.modalTitle.textContent="Edita sÃ­mbolo grÃ¡fico";
  const item=editar?simbolosSelecionado():null;
  simbolosCfg.modalBackdrop.dataset.editId=editar&&item?String(item.id):"";
  simbolosCfg.modalNome.value=item?.descricao||"";
  simbolosCfg.modalEspecialidade.value=item?.especialidade!=null?String(item.especialidade):"";
  simbolosCfg.modalBackdrop.classList.remove("hidden");
}
