async function planoCarregar(){const{res,data}=await requestJson("GET","/cadastros/grupos",undefined,true);if(!res.ok){footerMsg.textContent=data.detail||"Falha ao carregar plano de contas.";return}gruposCache=Array.isArray(data)?data:[];grupoSelId=gruposCache.length?gruposCache[0].id:null;catSelId=null;planoRenderGrupos();planoRenderCats()}
function planoRenderGrupos(){plano.tbGrupos.innerHTML=gruposCache.map(g=>`<tr data-id="${g.id}" class="${g.id===grupoSelId?"selected":""}"><td style="width:1px;display:none">${g.id}</td><td>${esc(g.nome)}</td><td>${esc(g.tipo)}</td></tr>`).join("")}
function planoRenderCats(){const g=gruposCache.find(x=>x.id===grupoSelId);const cats=g?.categorias||[];plano.tbCats.innerHTML=cats.map(c=>`<tr data-id="${c.id}" class="${c.id===catSelId?"selected":""}"><td>${esc(c.nome)}</td></tr>`).join("")}
async function planoAbrir(){planoEnsureUI();hideAllPanels();ensurePanelChrome(plano.panel);plano.panel.classList.remove("hidden");workspaceEmpty.classList.add("hidden");await planoCarregar()}
function planoGrupoSel(){return gruposCache.find(x=>x.id===grupoSelId)||null}
