function planoDialogGrupo(ed=null){cadModalAbrir(`<div class="f"><label>Nome</label><input id="cad-nome" value="${esc(ed?.nome||"")}"></div><div class="f"><label>Tipo</label><select id="cad-tipo"><option ${ed?.tipo==="Profissional"?"selected":""}>Profissional</option><option ${ed?.tipo==="Pessoal"?"selected":""}>Pessoal</option></select></div>`,async()=>{const nome=document.getElementById("cad-nome").value.trim();const tipo=document.getElementById("cad-tipo").value;if(!nome){window.alert("Informe o nome do grupo.");return false}const method=ed?"PUT":"POST";const path=ed?`/cadastros/grupos/${ed.id}`:"/cadastros/grupos";const{res,data}=await requestJson(method,path,{nome,tipo},true);if(!res.ok){window.alert(data.detail||"Falha ao salvar grupo.");return false}await planoCarregar()})}
async function planoDialogCategoria(ed=null){const gid=grupoSelId||ed?.grupo_id;if(!gid){window.alert("Selecione um grupo.");return}const op=gruposCache.map(g=>`<option value="${g.id}" ${g.id===gid?"selected":""}>${esc(g.nome)}</option>`).join("");cadModalAbrir(`<div class="f"><label>Nome</label><input id="cad-nome" value="${esc(ed?.nome||"")}"></div><div class="f"><label>Grupo</label><select id="cad-grupo">${op}</select></div><div class="f"><label>Tipo</label><select id="cad-tipo"><option ${ed?.tipo==="SaÃ­da"||ed?.tipo==="Saida"?"selected":""}>SaÃ­da</option><option ${ed?.tipo==="Entrada"?"selected":""}>Entrada</option></select></div><div class="f"><label><input id="cad-trib" type="checkbox" ${ed?.tributavel?"checked":""}> Categoria tributÃ¡vel</label></div>`,async()=>{const nome=document.getElementById("cad-nome").value.trim();const grupo_id=Number(document.getElementById("cad-grupo").value||0);const tipo=document.getElementById("cad-tipo").value;const tributavel=document.getElementById("cad-trib").checked;if(!nome){window.alert("Informe o nome da categoria.");return false}const method=ed?"PUT":"POST";const path=ed?`/cadastros/categorias/${ed.id}`:"/cadastros/categorias";const{res,data}=await requestJson(method,path,{nome,tipo,grupo_id,tributavel},true);if(!res.ok){window.alert(data.detail||"Falha ao salvar categoria.");return false}await planoCarregar();grupoSelId=grupo_id;planoRenderCats()})}
async function planoExcluirGrupo(){const g=planoGrupoSel();if(!g){window.alert("Selecione um grupo.");return}if(!window.confirm("Deseja eliminar este grupo?"))return;const{res,data}=await requestJson("DELETE",`/cadastros/grupos/${g.id}`,undefined,true);if(!res.ok){window.alert(data.detail||"NÃ£o foi possÃ­vel eliminar grupo.");return}await planoCarregar()}
