function usersPermModuleName(item){if(!item)return"";return String(item?.nome||item?.descricao||item?.name||"").trim()||usersPermModuleCode(item)}
function usersPermFunctionCode(item){if(!item)return"";const code=item?.codigo??item?.id??item?.id_funcao??item?.ID_FUNCAO??item;return String(code||"").trim()}
function usersPermFunctionName(item){if(item&&typeof item==="object")return String(item?.nome||item?.descricao||item?.name||"").trim()||usersPermFunctionCode(item);return String(item||"").trim()}
function usersPermSortKey(value){return usersNormalizeText(value||"")}
function usersPermSortModules(list){const items=Array.isArray(list)?list.slice():[];items.sort((a,b)=>{const na=usersPermSortKey(usersPermModuleName(a));const nb=usersPermSortKey(usersPermModuleName(b));if(na<nb)return-1;if(na>nb)return 1;const ca=usersPermModuleCode(a);const cb=usersPermModuleCode(b);return ca.localeCompare(cb,undefined,{numeric:true,sensitivity:"base"})});return items}
