function usersRenderAdvanced(){if(!usersCache.length){usersTbody.innerHTML='<tr><td colspan="5">Sem usuarios.</td></tr>';usersSelecionadoId=null;usersAtualizarAcoesToolbar();return}usersTbody.innerHTML=usersCache.map(u=>{const conectado=u.online?'<span style="color:#0a7a00">Sim</span>':'<span style="color:#1f2937">NÃ£o</span>';const status=u.ativo?'<span title="Ativo" style="color:#0a7a00;font-size:18px;line-height:1">â—</span>':'<span title="Inativo" style="color:#b00020;font-size:18px;line-height:1">â—</span>';return`<tr data-id="${u.id}"><td>${esc(u.nome||"-")}</td><td>${esc(u.apelido||"-")}</td><td>${esc(u.tipo_usuario||"-")}</td><td>${conectado}</td><td>${status}</td></tr>`}).join("");const existeSelecionado=usersCache.some(u=>Number(u.id||0)===Number(usersSelecionadoId||0));if(!existeSelecionado)usersSelecionadoId=Number(usersCache[0]?.id||0)||null;if(usersSelecionadoId)usersSelecionar(usersSelecionadoId);else usersAtualizarAcoesToolbar()}
async function carregarUsuarios(silent=false){if(!silent)setUsersStatus("",false);try{let res,data;if(usersGrantOverride){({res,data}=await requestJsonBase("GET","/admin/users",undefined,true,{"X-Protected-Grant":usersGrantOverride}));if(res&&res.ok){usersCache=Array.isArray(data)?data:[];usersRenderAdvanced();return}}({res,data}=await requestJson("GET","/admin/users",undefined,true));if(!res.ok){setUsersStatus(data.detail||"Falha ao carregar usuarios.",true);return}usersCache=Array.isArray(data)?data:[];usersRenderAdvanced()}catch{setUsersStatus("Erro de conexao ao carregar usuarios.",true)}}
