function usersPermSetTab(tab){usersPermActiveTab=(tab==="perfis")?"perfis":"acesso";if(usersPermTabAcessoBtn)usersPermTabAcessoBtn.classList.toggle("active",usersPermActiveTab==="acesso");if(usersPermTabPerfisBtn)usersPermTabPerfisBtn.classList.toggle("active",usersPermActiveTab==="perfis");if(usersPermTabAcesso)usersPermTabAcesso.classList.toggle("hidden",usersPermActiveTab!=="acesso");if(usersPermTabPerfis)usersPermTabPerfis.classList.toggle("hidden",usersPermActiveTab!=="perfis");if(usersPermActiveTab==="perfis"){usersPerfLoad()}}
function usersPermGetProfileByCode(codigo){const key=String(codigo||"").trim();return(Array.isArray(usersPermProfiles)?usersPermProfiles:[]).find(item=>String(item?.codigo||"").trim()===key)||null}
function usersPermSelecionarFuncao(codigo,focusWrap=false){if(usersPermFunctionWrap&&!usersPermFunctionWrap.dataset.keybind){usersPermFunctionWrap.dataset.keybind="1";usersPermFunctionWrap.addEventListener("keydown",usersPermHandleFunctionKeydown)}usersPermSelectedFuncId=String(codigo||"").trim();usersPermSelectionScope="func";usersPermFuncTbody?.querySelectorAll?.("tr[data-func]")?.forEach(tr=>tr.classList.toggle("selected",String(tr.getAttribute("data-func")||"")===usersPermSelectedFuncId));if(focusWrap&&usersPermFunctionWrap)usersPermFunctionWrap.focus({preventScroll:true});usersPermSyncFuncRadios()}
function usersPermRenderFuncoes(){if(!usersPermFuncTbody)return;const modulo=String(usersPermSelectedModule||"").trim();if(!modulo){usersPermFuncTbody.innerHTML="";usersPermSelectedFuncId="";usersPermSyncFuncRadios();return}const nivelModulo=usersPermNormalizeLevel(usersPermCurrent?.[modulo]);const funcoes=usersPermGetFunctionsForModule(modulo);if(!funcoes.length){usersPermFuncTbody.innerHTML="";usersPermSelectedFuncId="";usersPermSyncFuncRadios();return}usersPermFuncTbody.innerHTML=funcoes.map(fn=>{const codigo=usersPermFunctionCode(fn);const nome=usersPermFunctionName(fn);const nivel=usersPermFuncLevel(codigo,nivelModulo);const selected=String(codigo)===String(usersPermSelectedFuncId);return`<tr data-func="${esc(codigo)}"${selected?" class=\"selected\"":""}><td class="perm-label">${esc(nome)}</td><td class="perm-icon">${usersPermIcon(nivel)}</td></tr>`}).join("");Array.from(usersPermFuncTbody.querySelectorAll("tr[data-func]")).forEach(tr=>{tr.addEventListener("click",()=>usersPermSelecionarFuncao(tr.getAttribute("data-func"),true))});const existeSelecionado=funcoes.some(fn=>String(usersPermFunctionCode(fn))===String(usersPermSelectedFuncId));if(!existeSelecionado){const first=funcoes[0];usersPermSelectedFuncId=usersPermFunctionCode(first)}usersPermSelecionarFuncao(usersPermSelectedFuncId)}
function usersPermSelecionarModulo(codigo,focusWrap=false){if(usersPermModuleWrap&&!usersPermModuleWrap.dataset.keybind){usersPermModuleWrap.dataset.keybind="1";usersPermModuleWrap.addEventListener("keydown",usersPermHandleModuleKeydown)}usersPermSelectedModule=String(codigo||"").trim();usersPermSelectionScope="module";usersPermTbody?.querySelectorAll?.("tr[data-module]")?.forEach(tr=>tr.classList.toggle("selected",String(tr.getAttribute("data-module")||"")===usersPermSelectedModule));if(focusWrap&&usersPermModuleWrap)usersPermModuleWrap.focus({preventScroll:true});usersPermRenderFuncoes();usersPermSyncModuleRadios()}
function usersPermGetRows(selector,tbody){if(!tbody)return[];return Array.from(tbody.querySelectorAll(selector))}
function usersPermMoveSelection(rows,direction,kind){if(!rows.length)return;const idxAtual=rows.findIndex(r=>r.classList.contains("selected"));let next=idxAtual;if(next<0)next=0;else next+=direction;next=Math.max(0,Math.min(rows.length-1,next));const row=rows[next];if(!row)return;const attr=kind==="module"?"data-module":"data-func";const codigo=row.getAttribute(attr);if(kind==="module"){usersPermSelecionarModulo(codigo,true)}else{usersPermSelecionarFuncao(codigo,true)}row.scrollIntoView({block:"nearest"})}
function usersPermHandleModuleKeydown(ev){if(ev.key!=="ArrowUp"&&ev.key!=="ArrowDown")return;ev.preventDefault();const rows=usersPermGetRows("tr[data-module]",usersPermTbody);const dir=ev.key==="ArrowDown"?1:-1;usersPermMoveSelection(rows,dir,"module")}
function usersPermHandleFunctionKeydown(ev){if(ev.key!=="ArrowUp"&&ev.key!=="ArrowDown")return;ev.preventDefault();const rows=usersPermGetRows("tr[data-func]",usersPermFuncTbody);const dir=ev.key==="ArrowDown"?1:-1;usersPermMoveSelection(rows,dir,"func")}
function usersPermRenderPerfilPreview(){if(!usersPermProfilePreviewTbody)return;const perfil=usersPermGetProfileByCode(usersPermSelectedProfileCode);const basePerms=(perfil&&typeof perfil.permissoes==="object")?perfil.permissoes:{};usersPermProfilePreviewTbody.innerHTML=(Array.isArray(usersPermModules)?usersPermModules:[]).map(item=>{const codigo=usersPermModuleCode(item);const nome=usersPermModuleName(item)||codigo;const nivel=usersPermNormalizeLevel(basePerms?.[codigo]);return`<tr><td class="perm-label">${esc(nome)}</td><td class="perm-icon">${usersPermIcon(nivel)}</td><td>${esc(nivel)}</td></tr>`}).join("")}
function usersPermRenderProfiles(){if(!usersPermProfileSelect)return;const perfis=Array.isArray(usersPermProfiles)?usersPermProfiles:[];usersPermProfileSelect.innerHTML=perfis.map(item=>`<option value="${esc(String(item?.codigo||""))}">${esc(String(item?.nome||""))}</option>`).join("");if(!usersPermSelectedProfileCode&&perfis.length)usersPermSelectedProfileCode=String(perfis[0].codigo||"");if(usersPermSelectedProfileCode)usersPermProfileSelect.value=usersPermSelectedProfileCode;usersPermRenderPerfilPreview()}
function usersPerfSelectPerfil(perfilId){usersPerfSelectedPerfilId=perfilId?Number(perfilId):null;usersPerfRenderProfiles();usersPerfRenderPrestadores()}
function usersPerfRenderProfiles(){if(!usersPerfProfileTbody)return;const perfis=Array.isArray(usersPerfProfiles)?usersPerfProfiles:[];const selected=Number(usersPerfSelectedPerfilId||0);usersPerfProfileTbody.innerHTML=perfis.map(item=>{const pid=Number(item?.id||0);const nome=String(item?.nome||"");return`<tr data-perfil="${pid}"${pid===selected?" class=\"selected\"":""}><td class="perm-label">${esc(nome)}</td></tr>`}).join("");Array.from(usersPerfProfileTbody.querySelectorAll("tr[data-perfil]")).forEach(tr=>{tr.addEventListener("click",()=>usersPerfSelectPerfil(tr.getAttribute("data-perfil")))})}
function usersPerfRenderPrestadores(){if(!usersPerfPrestadoresWrap)return;const prestadores=Array.isArray(usersPerfPrestadores)?usersPerfPrestadores:[];const perfilKey=String(usersPerfSelectedPerfilId||"");const selectedSet=new Set((usersPerfAssignments&&usersPerfAssignments[perfilKey])||[]);usersPerfPrestadoresWrap.innerHTML=prestadores.map(item=>{const pid=Number(item?.id||0);const nome=String(item?.nome||"");const inativo=!!item?.inativo;const checked=selectedSet.has(pid);return`<label class="${inativo?"inativo":""}"><input type="checkbox" data-prestador="${pid}" ${checked?"checked":""}>${esc(nome)}</label>`}).join("");Array.from(usersPerfPrestadoresWrap.querySelectorAll("input[type=\"checkbox\"][data-prestador]")).forEach(inp=>{inp.addEventListener("change",usersPerfHandlePrestadorChange)})}
async function usersPerfHandlePrestadorChange(){if(!usersPermEditId||!usersPerfSelectedPerfilId)return;const checkedIds=Array.from(usersPerfPrestadoresWrap.querySelectorAll("input[type=\"checkbox\"][data-prestador]:checked")).map(inp=>Number(inp.getAttribute("data-prestador")||0)).filter(n=>n>0);const payload={perfil_id:Number(usersPerfSelectedPerfilId),prestador_ids:checkedIds};const{res,data}=await requestJson("PATCH",`/admin/users/${usersPermEditId}/profiles`,payload,true);if(!res.ok){window.alert(data.detail||"Falha ao salvar perfil.");return}usersPerfAssignments[String(usersPerfSelectedPerfilId)]=checkedIds}
async function usersPerfLoad(){if(!usersPermEditId)return;const{res,data}=await requestJson("GET",`/admin/users/${usersPermEditId}/profiles`,undefined,true);if(!res.ok){return}usersPerfProfiles=Array.isArray(data?.profiles)?data.profiles:[];usersPerfPrestadores=Array.isArray(data?.prestadores)?data.prestadores:[];usersPerfAssignments=(data&&typeof data.assignments==="object"&&data.assignments)?data.assignments:{};if(!usersPerfSelectedPerfilId&&usersPerfProfiles.length){usersPerfSelectedPerfilId=Number(usersPerfProfiles[0].id||0)||null}usersPerfRenderProfiles();usersPerfRenderPrestadores()}
function usersPermInferProfileCode(tipoUsuario){const tipoNorm=String(tipoUsuario||"").trim().toLowerCase();if(!tipoNorm)return"";const perfis=Array.isArray(usersPermProfiles)?usersPermProfiles:[];const byTipo=perfis.find(item=>String(item?.tipo_usuario||"").trim().toLowerCase()===tipoNorm);return byTipo?String(byTipo.codigo||""):""}
function usersPermAplicarPerfilSelecionado(){const perfil=usersPermGetProfileByCode(usersPermSelectedProfileCode);if(!perfil||typeof perfil.permissoes!=="object"){window.alert("Selecione um perfil vÃ¡lido.");return}const next={...(usersPermCurrent||{})};Object.keys(perfil.permissoes||{}).forEach(codigo=>{next[codigo]=usersPermNormalizeLevel(perfil.permissoes[codigo])});usersPermCurrent=next;usersRenderPermissoes(usersPermModules,usersPermLevels,usersPermCurrent);usersPermSetTab("acesso")}
function usersFecharPermissoes(){usersPermFlushAutoSave();if(usersPermBackdrop)usersPermBackdrop.classList.add("hidden");usersPermEditId=null;usersPermModules=[];usersPermLevels=[];usersPermCurrent={};usersPermSelectedModule="";usersPermProfiles=[];usersPermSelectedProfileCode="";usersPermFunctionsByModule={};usersPermFuncLevels={};usersPermSelectedFuncId="";usersPermEasyMode=false;usersPerfProfiles=[];usersPerfPrestadores=[];usersPerfAssignments={};usersPerfSelectedPerfilId=null;usersPermSetTab("acesso")}
function usersRenderPermissoes(modules,levels,permissoes){const ordered=usersPermSortModules(Array.isArray(modules)?modules:[]);usersPermModules=ordered;usersPermLevels=Array.isArray(levels)&&levels.length?levels:["desabilitado","protegido","habilitado"];if(!usersPermTbody)return;const current={};usersPermModules.forEach(item=>{const codigo=usersPermModuleCode(item);if(!codigo)return;current[codigo]=usersPermNormalizeLevel(permissoes?.[codigo])});usersPermCurrent=current;usersPermTbody.innerHTML=usersPermModules.map(item=>{const codigo=usersPermModuleCode(item);const nome=usersPermModuleName(item)||codigo;const nivel=usersPermNormalizeLevel(usersPermCurrent?.[codigo]);return`<tr data-module="${esc(codigo)}"><td class="perm-label">${esc(nome)}</td><td class="perm-icon">${usersPermIcon(nivel)}</td></tr>`}).join("");Array.from(usersPermTbody.querySelectorAll("tr[data-module]")).forEach(tr=>{tr.addEventListener("click",()=>usersPermSelecionarModulo(tr.getAttribute("data-module"),true))});
const existeSelecionado=usersPermModules.some(item=>usersPermModuleCode(item)===usersPermSelectedModule);if(!existeSelecionado)usersPermSelectedModule=usersPermModuleCode(usersPermModules?.[0])||"";usersPermSelecionarModulo(usersPermSelectedModule);usersPermRenderPerfilPreview();usersPermSyncModuleRadios()}
async function usersAbrirPermissoes(){const u=usersAtualSelecionado();if(!u){window.alert("Selecione um usuario.");return}if(!usersCanManageSelected(u)){window.alert("Conta base 'ClÃ­nica' Ã© protegida.");return}try{await usersCarregarPermissoesSchema();const{res,data}=await requestJson("GET",`/admin/users/${u.id}/permissions`,undefined,true);if(!res.ok){window.alert(data.detail||"Falha ao carregar permissÃµes.");return}usersPermEditId=Number(u.id||0)||null;usersPerfSelectedPerfilId=null;const easySchema=Array.isArray(usersPermSchema?.easy_modules)&&usersPermSchema.easy_modules.length?usersPermSchema.easy_modules:[];const easyLevels=Array.isArray(usersPermSchema?.easy_levels)&&usersPermSchema.easy_levels.length?usersPermSchema.easy_levels:[];const easyFuncs=(usersPermSchema&&typeof usersPermSchema.easy_functions_by_module==="object"&&usersPermSchema.easy_functions_by_module)?usersPermSchema.easy_functions_by_module:{};usersPermEasyMode=easySchema.length>0;usersPermModules=usersPermEasyMode?easySchema:(Array.isArray(data?.modules)?data.modules:(usersPermSchema?.modules||[]));usersPermLevels=usersPermEasyMode?(easyLevels.length?easyLevels:usersPermSchema?.levels||["desabilitado","protegido","habilitado"]):(Array.isArray(data?.levels)&&data.levels.length?data.levels:(usersPermSchema?.levels||["desabilitado","protegido","habilitado"]));usersPermProfiles=Array.isArray(usersPermSchema?.profiles)?usersPermSchema.profiles:[];const rawFunctions=usersPermEasyMode?easyFuncs:((usersPermSchema&&typeof usersPermSchema.functions_by_module==="object"&&usersPermSchema.functions_by_module)?usersPermSchema.functions_by_module:{});usersPermFunctionsByModule=usersPermNormalizeFunctionsByModule(rawFunctions);usersPermFuncLevels=usersPermEasyMode&&(data&&typeof data.easy_funcoes==="object"&&data.easy_funcoes)?data.easy_funcoes:{};if(usersPermNome)usersPermNome.value=String(data?.nome||u.nome||"");if(usersPermTipo)usersPermTipo.value=String(data?.tipo_usuario||u.tipo_usuario||"");if(usersPermTitleName)usersPermTitleName.textContent=String(data?.nome||u.nome||"usuÃ¡rio");const alvoAdmin=Boolean(u?.is_admin);if(usersPermTabPerfisBtn)usersPermTabPerfisBtn.classList.toggle("hidden",alvoAdmin);if(alvoAdmin&&usersPermTabPerfis)usersPermTabPerfis.classList.add("hidden");if(alvoAdmin&&usersPermActiveTab==="perfis")usersPermActiveTab="acesso";usersPermSelectedProfileCode=usersPermInferProfileCode(data?.tipo_usuario||u.tipo_usuario||"")||String(usersPermProfiles?.[0]?.codigo||"");usersPermRenderProfiles();const permsPayload=usersPermEasyMode?(data?.easy_modules||{}):(data?.permissoes||{});usersRenderPermissoes(usersPermModules,usersPermLevels,permsPayload);usersPermSetTab("acesso");usersPermBackdrop.classList.remove("hidden");usersPermSyncModuleRadios();usersPermSyncFuncRadios()}catch(err){window.alert(err?.message||"Falha ao abrir permissÃµes.")}}
async function usersSalvarPermissoes(){if(!usersPermEditId){window.alert("UsuÃ¡rio nÃ£o selecionado.");return}const payload=usersPermBuildPayload();const{res,data}=await requestJson("PATCH",`/admin/users/${usersPermEditId}/permissions`,payload,true);if(!res.ok){window.alert(data.detail||"Falha ao salvar permissÃµes.");return}usersFecharPermissoes();setUsersStatus(data.detail||"PermissÃµes atualizadas com sucesso.",false);await carregarUsuarios(true)}
const setSaStatus=(m,e)=>{if(!sa.status)return;sa.status.textContent=m||"";sa.status.className="users-status "+(e?"err":"ok")};
const isSuperAdminSessao=()=>!!(sessaoAtual&&sessaoAtual.is_superadmin);
const saMoney=v=>Number(v||0).toLocaleString("pt-BR",{style:"currency",currency:"BRL"});
function saRenderOverview(d){if(!d)return;sa.totalClinicas.value=String(d.total_clinicas??0);sa.totalUsuarios.value=String(d.total_usuarios??0);sa.mrr.value=saMoney(d.mrr_estimado||0);sa.arr.value=saMoney(d.arr_estimado||0);sa.clinicasAtivas.value=String(d.clinicas_ativas??0);sa.clinicasTrial.value=String(d.clinicas_trial??0);sa.clinicasExpiradas.value=String(d.clinicas_expiradas??0);sa.clinicasSuspensas.value=String(d.clinicas_suspensas??0);if(sa.clinicasSemUsuario)sa.clinicasSemUsuario.value=String(d.clinicas_sem_usuario??0);if(sa.clinicasArquivadas)sa.clinicasArquivadas.value=String(d.clinicas_arquivadas??0);if(sa.onlineSummary)sa.onlineSummary.textContent=d.online_resumo||"Nenhum usuÃ¡rio online."}
function saRenderClinicas(){
  if(!saClinicasCache.length){sa.tbClinicas.innerHTML='<tr><td colspan="8">Sem clinicas.</td></tr>';return}
  sa.tbClinicas.innerHTML=saClinicasCache.map(c=>{
    const protegido=!!c.is_owner_clinica;
    const acoes=protegido
      ? `<div class="users-actions">
          <input class="sa-trial-days" data-sa-days-id="${c.id}" type="number" min="1" max="3650" value="10" title="Dias extras de teste">
          <button class="btn-mini" data-sa-action="trial-extra" data-id="${c.id}" type="button">+Teste</button>
          <button class="btn-mini" data-sa-action="toggle" data-id="${c.id}" type="button">${c.ativo?"Suspender":"Ativar"}</button>
          <button class="btn-mini" data-sa-action="demo" data-id="${c.id}" type="button">Demo</button>
          <button class="btn-mini" data-sa-action="mensal" data-id="${c.id}" type="button">Mensal</button>
          <button class="btn-mini" data-sa-action="anual" data-id="${c.id}" type="button">Anual</button>
          <button class="btn-mini" data-sa-action="superadmin" data-id="${c.id}" type="button">Super Admin</button>
          <button class="btn-mini" data-sa-action="novo-user" data-id="${c.id}" type="button">Novo usuÃ¡rio</button>
          <span style="color:#64748b;align-self:center">Owner</span>
        </div>`
      : `<div class="users-actions">
          <input class="sa-trial-days" data-sa-days-id="${c.id}" type="number" min="1" max="3650" value="10" title="Dias extras de teste">
          <button class="btn-mini" data-sa-action="trial-extra" data-id="${c.id}" type="button">+Teste</button>
          <button class="btn-mini" data-sa-action="toggle" data-id="${c.id}" type="button">${c.ativo?"Suspender":"Ativar"}</button>
          <button class="btn-mini" data-sa-action="demo" data-id="${c.id}" type="button">Demo</button>
          <button class="btn-mini" data-sa-action="mensal" data-id="${c.id}" type="button">Mensal</button>
          <button class="btn-mini" data-sa-action="anual" data-id="${c.id}" type="button">Anual</button>
          <button class="btn-mini" data-sa-action="superadmin" data-id="${c.id}" type="button">Super Admin</button>
          <button class="btn-mini" data-sa-action="novo-user" data-id="${c.id}" type="button">Novo usuÃ¡rio</button>
          <button class="btn-mini" data-sa-action="excluir-clinica" data-id="${c.id}" type="button" style="border-color:#fecaca;color:#991b1b">Excluir</button>
        </div>`;
    return `<tr data-id="${c.id}">
      <td>${c.id}</td>
      <td>${esc(c.nome)}</td>
      <td>${esc(c.email)}</td>
      <td>${esc(c.tipo_conta||"-")}</td>
      <td>${esc(c.assinatura_status||"-")}</td>
      <td>${esc(c.trial_ate?String(c.trial_ate).slice(0,10):"-")}</td>
      <td>${c.usuarios_ativos||0}/${c.usuarios_total||0}</td>
      <td>${acoes}</td>
    </tr>`;
  }).join("")
}
function saRenderUsuarios(){if(!Array.isArray(saUsuariosCache)||!saUsuariosCache.length){sa.tbUsuarios.innerHTML='<tr><td colspan="11">Sem usuarios.</td></tr>';return}sa.tbUsuarios.innerHTML=saUsuariosCache.map(u=>`<tr data-id="${u.id}"><td>${u.id}</td><td>${esc(u.nome||"-")}${u.is_owner_account?' <strong>(Owner)</strong>':''}</td><td>${esc(u.email||"-")}</td><td>${esc(u.clinica_nome||("- #"+(u.clinica_id??"-")))}</td><td>${esc(u.clinica_email||"-")}</td><td>${esc(u.clinica_plano||u.clinica_tipo_conta||"-")}</td><td>${esc(u.clinica_status||"-")}</td><td>${esc(u.clinica_trial_ate?String(u.clinica_trial_ate).slice(0,10):"-")}</td><td>${u.is_admin?"Admin":"Usuario"}</td><td>${u.ativo?"Ativo":"Inativo"}</td><td>${u.is_owner_account?'<span style="color:#64748b">Protegido</span>':`<div class="users-actions"><button class="btn-mini" data-sa-user-action="toggle-status" data-id="${u.id}" type="button">${u.ativo?"Desativar":"Ativar"}</button><button class="btn-mini" data-sa-user-action="toggle-admin" data-id="${u.id}" type="button">${u.is_admin?"Remover admin":"Tornar admin"}</button><button class="btn-mini" data-sa-user-action="reset-senha" data-id="${u.id}" type="button">Reset senha</button></div>`}</td></tr>`).join("")}
function saRenderCobrancas(lista){if(!Array.isArray(lista)||!lista.length){sa.tbCobrancas.innerHTML='<tr><td colspan="7">Sem cobrancas.</td></tr>';return}sa.tbCobrancas.innerHTML=lista.map(x=>`<tr><td>${x.id}</td><td>${esc(x.clinica_nome||("#"+x.clinica_id))}</td><td>${esc(x.plano||"-")}</td><td>${esc(x.status||"-")}</td><td>${saMoney(x.valor||0)}</td><td>${esc(x.origem||"-")}</td><td>${esc(x.criado_em?String(x.criado_em).replace("T"," ").slice(0,19):"-")}</td></tr>`).join("")}
function saRenderAuditoria(lista){if(!Array.isArray(lista)||!lista.length){sa.tbAuditoria.innerHTML='<tr><td colspan="5">Sem auditoria.</td></tr>';return}sa.tbAuditoria.innerHTML=lista.map(x=>`<tr><td>${x.id}</td><td>${esc(x.criado_em?String(x.criado_em).replace("T"," ").slice(0,19):"-")}</td><td>${esc(x.acao||"-")}</td><td>${esc(x.actor_email||"-")}</td><td>${esc((x.alvo_tipo||"-")+(x.alvo_id?("#"+x.alvo_id):""))}</td></tr>`).join("")}
async function saCarregarOverview(){const{res,data}=await requestJson("GET","/superadmin/overview",undefined,true);if(!res.ok)throw new Error(data.detail||"Falha ao carregar overview.");saRenderOverview(data)}
async function saCarregarClinicas(){const q=encodeURIComponent((sa.q?.value||"").trim());const st=encodeURIComponent(sa.statusFiltro?.value||"todas");const{res,data}=await requestJson("GET",`/superadmin/clinicas?q=${q}&status=${st}`,undefined,true);if(!res.ok)throw new Error(data.detail||"Falha ao carregar clinicas.");saClinicasCache=Array.isArray(data)?data:[];saRenderClinicas()}
function saUsuariosQueryParams(limit){const params=new URLSearchParams();params.set("limit",String(limit||200));const q=(sa.usuariosQ?.value||"").trim();if(q)params.set("q",q);const ativo=(sa.usuariosAtivo?.value||"todos").toLowerCase();if(ativo==="ativo")params.set("ativo","true");else if(ativo==="inativo")params.set("ativo","false");const admin=(sa.usuariosAdmin?.value||"todos").toLowerCase();if(admin==="admin")params.set("admin","true");else if(admin==="usuario")params.set("admin","false");const plano=(sa.usuariosPlano?.value||"TODOS").toUpperCase();if(plano!=="TODOS")params.set("plano",plano);const clinicaStatus=(sa.usuariosClinicaStatus?.value||"todas").toLowerCase();if(clinicaStatus!=="todas")params.set("clinica_status",clinicaStatus);return params}
async function saCarregarUsuarios(){const qs=saUsuariosQueryParams(200).toString();const{res,data}=await requestJson("GET",`/superadmin/usuarios?${qs}`,undefined,true);if(!res.ok)throw new Error(data.detail||"Falha ao carregar usuarios da plataforma.");saUsuariosCache=Array.isArray(data)?data:[];saRenderUsuarios()}
async function saExportarUsuariosCsv(){if(!isSuperAdminSessao())return;try{const token=getToken();if(!token)throw new Error("Sessao invalida para exportar CSV.");const qs=saUsuariosQueryParams(5000).toString();const res=await fetch(`${baseUrl}/superadmin/usuarios/export.csv?${qs}`,{headers:{Authorization:"Bearer "+token}});if(!res.ok){let data={};try{data=await res.json()}catch{}throw new Error(data.detail||"Falha ao exportar CSV de usuarios.")}const blob=await res.blob();let fileName="usuarios_plataforma.csv";const cd=res.headers.get("content-disposition")||"";const m=cd.match(/filename\s*=\s*"?([^";]+)"?/i);if(m&&m[1])fileName=m[1];const blobUrl=URL.createObjectURL(blob);const a=document.createElement("a");a.href=blobUrl;a.download=fileName;document.body.appendChild(a);a.click();a.remove();URL.revokeObjectURL(blobUrl);setSaStatus("CSV exportado com sucesso.",false)}catch(err){setSaStatus(err.message||"Falha ao exportar usuarios.",true)}}
async function saCarregarCobrancas(){const{res,data}=await requestJson("GET","/superadmin/cobrancas?limit=80",undefined,true);if(!res.ok)throw new Error(data.detail||"Falha ao carregar cobrancas.");saRenderCobrancas(Array.isArray(data)?data:[])}
async function saCarregarAuditoria(){const{res,data}=await requestJson("GET","/superadmin/auditoria?limit=80",undefined,true);if(!res.ok)throw new Error(data.detail||"Falha ao carregar auditoria.");saRenderAuditoria(Array.isArray(data)?data:[])}
async function saRecarregarTudo(){if(!isSuperAdminSessao())return;setSaStatus("",false);try{await saCarregarOverview();await saCarregarClinicas();await saCarregarUsuarios();await saCarregarCobrancas();await saCarregarAuditoria();setSaStatus("Painel atualizado.",false)}catch(err){setSaStatus(err.message||"Falha ao carregar Painel ADM.",true)}}
async function saAbrir(){if(!isSuperAdminSessao()){footerMsg.textContent="Acesso restrito ao Super Admin.";return}hideAllPanels();sa.panel.classList.remove("hidden");workspaceEmpty.classList.add("hidden");await saRecarregarTudo()}
const saNomeClinica=id=>{const item=saClinicasCache.find(x=>Number(x.id)===Number(id));return item?.nome||`#${id}`};
async function saAlterarStatusClinica(id,ativo){const nome=saNomeClinica(id);const acao=ativo?"ativar":"suspender";if(!window.confirm(`Confirmar ${acao} a clÃ­nica "${nome}"?`))return;const motivo=window.prompt("Motivo (opcional):","");if(motivo===null)return;const{res,data}=await requestJson("PATCH",`/superadmin/clinicas/${id}/status`,{ativo,motivo:motivo||""},true);if(!res.ok){window.alert(data.detail||"Falha ao atualizar status da clinica.");return}footerMsg.textContent=data.detail||"Status atualizado.";await saRecarregarTudo()}
async function saAlterarPlanoClinica(id,plano){const nome=saNomeClinica(id);const planoNorm=String(plano||"").trim().toUpperCase();const planoRotulo=planoNorm==="DEMO"?"Demo":planoNorm==="MENSAL"?"Mensal":planoNorm==="ANUAL"?"Anual":planoNorm==="SUPERADMIN"?"Super Admin":planoNorm;if(!window.confirm(`Aplicar o plano ${planoRotulo} para a clÃ­nica "${nome}"?`))return;let dias=null;if(planoNorm!=="SUPERADMIN"){const d=window.prompt("Dias de validade (deixe em branco para padrÃ£o do plano):","");if(d===null)return;if(String(d).trim()!==""){const n=Number(d);if(Number.isFinite(n)&&n>0)dias=Math.round(n)}}const payload={plano,manter_ativo:true};if(dias!==null)payload.dias=dias;const{res,data}=await requestJson("PATCH",`/superadmin/clinicas/${id}/plano`,payload,true);if(!res.ok){window.alert(data.detail||"Falha ao atualizar plano da clinica.");return}footerMsg.textContent=data.detail||"Plano atualizado.";await saRecarregarTudo()}
async function saProrrogarTesteClinica(id,dias){const qtd=Math.round(Number(dias||0));if(!Number.isFinite(qtd)||qtd<1){window.alert("Informe dias vÃ¡lidos (mÃ­nimo 1).");return}const nome=saNomeClinica(id);if(!window.confirm(`Prorrogar o perÃ­odo de teste da clÃ­nica "${nome}" por ${qtd} dias?`))return;const{res,data}=await requestJson("PATCH",`/superadmin/clinicas/${id}/trial-extra`,{dias:qtd},true);if(!res.ok){window.alert(data.detail||"Falha ao prorrogar perÃ­odo de teste.");return}footerMsg.textContent=data.detail||"PerÃ­odo de teste prorrogado.";await saRecarregarTudo()}
async function saExcluirClinica(id){const item=saClinicasCache.find(x=>Number(x.id)===Number(id));const nome=item?.nome||`#${id}`;if(!window.confirm(`Deseja excluir definitivamente a conta \"${nome}\"?\n\nEsta aÃ§Ã£o remove os dados da clÃ­nica e nÃ£o pode ser desfeita.`))return;const confirma=(window.prompt("Digite EXCLUIR para confirmar:","")||"").trim().toUpperCase();if(confirma!=="EXCLUIR"){window.alert("ConfirmaÃ§Ã£o invÃ¡lida. ExclusÃ£o cancelada.");return}const{res,data}=await requestJson("DELETE",`/superadmin/clinicas/${id}`,undefined,true);if(!res.ok){window.alert(data.detail||"Falha ao excluir conta.");return}footerMsg.textContent=data.detail||"Conta removida definitivamente.";await saRecarregarTudo()}
async function saCriarUsuarioClinica(clinicaId){const nomeClinica=saNomeClinica(clinicaId);const nome=window.prompt("Nome do novo usuario/admin:","")||"";if(!nome.trim())return;const email=window.prompt("E-mail do novo usuario/admin:","")||"";if(!email.trim())return;const senha=window.prompt("Senha inicial (minimo 6 caracteres):","")||"";if(String(senha).trim().length<6){window.alert("Senha deve ter no minimo 6 caracteres.");return}if(!window.confirm(`Criar o usuÃ¡rio admin "${nome.trim()}" para a clÃ­nica "${nomeClinica}"?`))return;const{res,data}=await requestJson("POST","/superadmin/usuarios",{clinica_id:clinicaId,nome:nome.trim(),email:email.trim(),senha:senha,is_admin:true,ativar_clinica:true},true);if(!res.ok){window.alert(data.detail||"Falha ao criar usuario para a clinica.");return}footerMsg.textContent=data.detail||"Usuario criado com sucesso.";await saRecarregarTudo()}
async function saAlterarStatusUsuario(id,ativo){const{res,data}=await requestJson("PATCH",`/superadmin/usuarios/${id}/status`,{ativo},true);if(!res.ok){window.alert(data.detail||"Falha ao atualizar status do usuario.");return}footerMsg.textContent=data.detail||"Status de usuario atualizado.";await saRecarregarTudo()}
async function saAlterarPerfilUsuario(id,isAdmin){const{res,data}=await requestJson("PATCH",`/superadmin/usuarios/${id}/perfil`,{is_admin:isAdmin},true);if(!res.ok){window.alert(data.detail||"Falha ao atualizar perfil do usuario.");return}footerMsg.textContent=data.detail||"Perfil de usuario atualizado.";await saRecarregarTudo()}
async function saResetarSenhaUsuario(id){const novaSenha=window.prompt("Nova senha (minimo 6 caracteres):","")||"";if(novaSenha.trim().length<6){window.alert("Senha deve ter no minimo 6 caracteres.");return}const{res,data}=await requestJson("POST",`/superadmin/usuarios/${id}/reset-senha`,{nova_senha:novaSenha.trim()},true);if(!res.ok){window.alert(data.detail||"Falha ao redefinir senha.");return}footerMsg.textContent=data.detail||"Senha redefinida com sucesso."}
async function carregarSessao(){const token=getToken();if(!token){loginWrap.classList.remove("hidden");shell.classList.add("hidden");showPanel(panelLogin);licUpdateBadge(null);if(btnOpenUsers)btnOpenUsers.classList.add("hidden");if(menuSuperAdminAction)menuSuperAdminAction.classList.add("hidden");if(menuSuperAdminSep)menuSuperAdminSep.classList.add("hidden");menuApplyPermissions();return}try{if(mpReturnPaymentId)await licConfirmarPagamentoRetorno();const res=await fetch(baseUrl+"/me",{headers:{Authorization:"Bearer "+token}});const data=await res.json();if(!res.ok){const detail=data.detail||"Sessao invalida.";if(res.status===403&&String(detail).toLowerCase().includes("expirada")){sessaoAtual=null;loginWrap.classList.remove("hidden");shell.classList.add("hidden");showPanel(panelLogin);setLoginStatus(detail,true);if(btnOpenUsers)btnOpenUsers.classList.add("hidden");try{await abrirLicencaModal()}catch{}menuApplyPermissions();return}setToken("");setLoginStatus(detail,true);loginWrap.classList.remove("hidden");shell.classList.add("hidden");showPanel(panelLogin);licUpdateBadge(null);if(btnOpenUsers)btnOpenUsers.classList.add("hidden");if(menuSuperAdminAction)menuSuperAdminAction.classList.add("hidden");if(menuSuperAdminSep)menuSuperAdminSep.classList.add("hidden");menuApplyPermissions();return}sessaoAtual=data;userEmail.textContent=data.email||"-";userRole.textContent="Perfil: "+(data.is_superadmin?"Super Admin":(data.is_admin?"Administrador":"Usuario"));if(btnOpenUsers)btnOpenUsers.classList.toggle("hidden",!(data.is_admin||data.is_superadmin));if(menuSuperAdminAction)menuSuperAdminAction.classList.toggle("hidden",!data.is_superadmin);if(menuSuperAdminSep)menuSuperAdminSep.classList.toggle("hidden",!data.is_superadmin);if(!data.is_admin)showUsersPanel(false);if(!data.is_superadmin&&sa&&sa.panel)sa.panel.classList.add("hidden");loginWrap.classList.add("hidden");shell.classList.remove("hidden");footerMsg.textContent="Sessao ativa para clinica_id "+(data.clinica_id??"-");try{await licCarregarInfo()}catch{licUpdateBadge(null)}menuApplyPermissions()}catch{if(btnOpenUsers)btnOpenUsers.classList.add("hidden");setLoginStatus("Nao foi possivel validar a sessao.",true);menuApplyPermissions()}}
const setTab=(n)=>{document.querySelectorAll(".tab-btn").forEach(b=>b.classList.toggle("active",b.getAttribute("data-tab")===n));document.getElementById("tab-fixo").classList.toggle("hidden",n!=="fixo");document.getElementById("tab-flex").classList.toggle("hidden",n!=="flex");document.getElementById("tab-custos").classList.toggle("hidden",n!=="custos")};
const atualizarDiasAno=()=>{c.lblDiasUteisAno.textContent=formatScenarioNum(toFloat(c.txtMesestrabalhados.value)*toFloat(c.txtDiasUteisMes.value));atualizarTotaisFixo()};
const atualizarTotaisFixo=()=>{const total=toFloat(c.txtHorasAtendimentoDia.value)*toFloat(c.lblDiasUteisAno.textContent)*Math.max(1,parseInt(c.txtNumConsultorios.value||"1",10));c.lblTotalHorasFixo.textContent=formatScenarioNum(total);c.lblTotalMinutosFixo.textContent=formatScenarioNum(total*60);c.lblTotalTurnosFixo.textContent=formatScenarioNum(total?total/4:0);atualizarComboHoras()};
const atualizarTotalDiaIndex=(i)=>{const soma=toFloat(c[`txtManha${i}`].value)+toFloat(c[`txtTarde${i}`].value)+toFloat(c[`txtNoite${i}`].value);const horas=soma*toFloat(c[`txtDiasAno${i}`].value);c[`lblTotalDia${i}`].textContent=formatScenarioNum(soma);c[`lblHorasAnoDia${i}`].textContent=formatScenarioNum(horas);atualizarTotaisFlex()};
const atualizarTotaisFlex=()=>{let total=0;for(let i=1;i<=6;i++)total+=toFloat(c[`lblHorasAnoDia${i}`].textContent);total*=Math.max(1,parseInt(c.txtNumConsultorios_2.value||"1",10));c.lblTotalHorasAnoFlex.textContent=formatScenarioNum(total);c.lblTotalMinutosFlex.textContent=formatScenarioNum(total*60);c.lblTotalTurnosFlex.textContent=formatScenarioNum(total?total/4:0);atualizarComboHoras()};
const atualizarComboHoras=()=>{const sel=c.cboHorasAno.value,fixo=toFloat(c.lblTotalHorasFixo.textContent),flex=toFloat(c.lblTotalHorasAnoFlex.textContent);c.cboHorasAno.innerHTML="";const a=document.createElement("option");a.value=MODO_HORAS_FIXO;a.textContent=MODO_HORAS_FIXO;a.dataset.horas=String(fixo);const b=document.createElement("option");b.value=MODO_HORAS_FLEX;b.textContent=MODO_HORAS_FLEX;b.dataset.horas=String(flex);c.cboHorasAno.append(a,b);c.cboHorasAno.value=isModoFlex(sel)?MODO_HORAS_FLEX:MODO_HORAS_FIXO;cboHorasAnoChange()};
const cboHorasAnoChange=()=>{const s=c.cboHorasAno.options[c.cboHorasAno.selectedIndex];c.txtHorasAno.value=formatScenarioNum(toFloat(s?s.dataset.horas:0));atualizarCustos()};
const atualizarCustos=()=>{const gasto=toFloat(c.txtGastoAnualParticular.value)+toFloat(c.txtGastoAnualEmpresa.value),horas=toFloat(c.txtHorasAno.value),cfph=horas?gasto/horas:0,cfpm=cfph?cfph/60:0;c.lblCustoAno.textContent=formatMoney(gasto);c.lblCFPH.textContent=formatScenarioNum(cfph);c.lblCFPM.textContent=formatScenarioNum(cfpm)};
const cenarioPayload=()=>{const turnos={};for(let i=1;i<=6;i++)turnos[String(i)]={manha:toFloat(c[`txtManha${i}`].value),tarde:toFloat(c[`txtTarde${i}`].value),noite:toFloat(c[`txtNoite${i}`].value),dias:toFloat(c[`txtDiasAno${i}`].value)};return{meses_trabalhados:toFloat(c.txtMesestrabalhados.value),dias_uteis_mes:toFloat(c.txtDiasUteisMes.value),dias_uteis_ano:toFloat(c.lblDiasUteisAno.textContent),horas_atendimento_dia:toFloat(c.txtHorasAtendimentoDia.value),num_consultorios:Math.max(1,parseInt(c.txtNumConsultorios.value||"1",10)),num_consultorios_flex:Math.max(1,parseInt(c.txtNumConsultorios_2.value||"1",10)),horas_ano:toFloat(c.txtHorasAno.value),modo_horas:c.cboHorasAno.value,gasto_anual_particular:toFloat(c.txtGastoAnualParticular.value),gasto_anual_empresa:toFloat(c.txtGastoAnualEmpresa.value),cartao:toFloat(c.txtCartao.value),ir:toFloat(c.txtIR.value),cd:toFloat(c.txtCD.value),custo_ano:toFloat(c.lblCustoAno.textContent),cfph:toFloat(c.lblCFPH.textContent),cfpm:toFloat(c.lblCFPM.textContent),total_horas_fixo:toFloat(c.lblTotalHorasFixo.textContent),total_minutos_fixo:toFloat(c.lblTotalMinutosFixo.textContent),total_turnos_fixo:toFloat(c.lblTotalTurnosFixo.textContent),total_horas_flex:toFloat(c.lblTotalHorasAnoFlex.textContent),total_minutos_flex:toFloat(c.lblTotalMinutosFlex.textContent),total_turnos_flex:toFloat(c.lblTotalTurnosFlex.textContent),turnos_flex:turnos}}
async function carregarCenario(){try{const{res,data}=await requestJson("GET","/cenario",undefined,true);if(!res.ok){footerMsg.textContent=data.detail||"Falha ao carregar cenario.";return}const d=data||{};c.txtMesestrabalhados.value=formatScenarioMes(d.meses_trabalhados||0);c.txtDiasUteisMes.value=formatScenarioNum(d.dias_uteis_mes||0);c.txtHorasAtendimentoDia.value=formatScenarioNum(d.horas_atendimento_dia||0);c.txtNumConsultorios.value=Math.max(1,parseInt(d.num_consultorios||1,10));c.txtNumConsultorios_2.value=Math.max(1,parseInt(d.num_consultorios_flex||d.num_consultorios||1,10));c.txtGastoAnualParticular.value=formatMoney(d.gasto_anual_particular||0);c.txtGastoAnualEmpresa.value=formatMoney(d.gasto_anual_empresa||0);c.txtCartao.value=formatScenarioNum(d.cartao||0);c.txtIR.value=formatScenarioNum(d.ir||0);c.txtCD.value=formatScenarioNum(d.cd||0);const t=d.turnos_flex||{};for(let i=1;i<=6;i++){const x=t[String(i)]||{manha:0,tarde:0,noite:0,dias:0};c[`txtManha${i}`].value=formatScenarioNum(x.manha||0);c[`txtTarde${i}`].value=formatScenarioNum(x.tarde||0);c[`txtNoite${i}`].value=formatScenarioNum(x.noite||0);c[`txtDiasAno${i}`].value=formatScenarioNum(x.dias||0);atualizarTotalDiaIndex(i)}atualizarDiasAno();atualizarTotaisFixo();atualizarTotaisFlex();c.cboHorasAno.value=isModoFlex(d.modo_horas)?MODO_HORAS_FLEX:MODO_HORAS_FIXO;cboHorasAnoChange();footerMsg.textContent="Cenario carregado."}catch{footerMsg.textContent="Erro de conexao ao carregar cenario."}}
async function salvarCenario(){try{const{res,data}=await postJson("/cenario",cenarioPayload(),true);footerMsg.textContent=res.ok?(data.detail||"Cenario salvo com sucesso."):(data.detail||"Falha ao salvar cenario.")}catch{footerMsg.textContent="Erro de conexao ao salvar cenario."}}
async function calcularFixosAno(){try{const ano=parseInt(c.box_Ano.value||"0",10);if(!ano){footerMsg.textContent="Informe um ano valido.";return}const{res,data}=await postJson("/cenario/calcular-fixos",{ano},true);if(!res.ok){footerMsg.textContent=data.detail||"Falha ao calcular fixos.";return}c.lblFixo_pessoal.textContent=formatMoney(data.fixo_pessoal||0);c.lblFixo_empresa.textContent=formatMoney(data.fixo_empresa||0);c.lblCusto_Anual.textContent=formatMoney(data.custo_anual||0);footerMsg.textContent="Calculo anual concluido."}catch{footerMsg.textContent="Erro de conexao ao calcular fixos."}}
