function fcxFmtMoeda(v){return Number(v||0).toLocaleString("pt-BR",{style:"currency",currency:"BRL"})}
function fcxValorNumerico(v){const n=Number(v||0);return Number.isFinite(n)?n:0}
function fcxLimparCanvas(canvas,msg,titulo){
  if(!canvas)return;
  const ctx=canvas.getContext("2d");
  const w=canvas.width,h=canvas.height;
  ctx.clearRect(0,0,w,h);
  ctx.fillStyle="#fff";
  ctx.fillRect(0,0,w,h);
  if(titulo){
    ctx.fillStyle="#111";
    ctx.textAlign="center";
    ctx.font="700 20px Tahoma";
    ctx.fillText(titulo,w/2,28);
  }
  if(msg){
    ctx.fillStyle="#666";
    ctx.textAlign="center";
    ctx.font="12px Tahoma";
    ctx.fillText(msg,w/2,h/2);
  }
}
function fcxRenderEvolucao(){
  const canvas=fcx?.canvasEvolucao;
  if(!canvas)return;
  const itens=Array.isArray(fcxData?.evolucao)?fcxData.evolucao:[];
  if(!itens.length){fcxLimparCanvas(canvas,"Sem dados para o perÃ­odo selecionado.","Desempenho do fluxo de caixa");return}
  const ctx=canvas.getContext("2d");
  const w=canvas.width,h=canvas.height;
  ctx.clearRect(0,0,w,h);
  ctx.fillStyle="#fff";
  ctx.fillRect(0,0,w,h);
  ctx.fillStyle="#111";
  ctx.textAlign="center";
  ctx.font="700 20px Tahoma";
  ctx.fillText("Desempenho do fluxo de caixa",w/2,28);
  const ml=56,mr=26,mt=52,mb=98,pw=w-ml-mr,ph=h-mt-mb;
  const maxY=Math.max(...itens.map(i=>Math.max(fcxValorNumerico(i.entrada),fcxValorNumerico(i.saida))),1);
  for(let i=0;i<=5;i++){
    const y=mt+ph*(i/5);
    ctx.strokeStyle="#d9e1ec";
    ctx.setLineDash([4,4]);
    ctx.beginPath();
    ctx.moveTo(ml,y);
    ctx.lineTo(ml+pw,y);
    ctx.stroke();
    ctx.setLineDash([]);
    const val=maxY*(1-i/5);
    ctx.fillStyle="#556170";
    ctx.textAlign="right";
    ctx.font="10px Tahoma";
    ctx.fillText(fcxFmtMoeda(val),ml-6,y+3);
  }
  const gw=pw/Math.max(1,itens.length);
  const bw=Math.min(22,gw*0.34);
  itens.forEach((it,idx)=>{
    const x=ml+gw*idx+gw/2;
    const ent=fcxValorNumerico(it.entrada);
    const sai=fcxValorNumerico(it.saida);
    const hEnt=(ent/maxY)*ph;
    const hSai=(sai/maxY)*ph;
    const yEnt=mt+ph-hEnt;
    const ySai=mt+ph-hSai;
    ctx.fillStyle=ent>sai?"#2ecc71":"#e74c3c";
    ctx.fillRect(x-bw-2,yEnt,bw,hEnt);
    ctx.fillStyle="#3498db";
    ctx.fillRect(x+2,ySai,bw,hSai);
    ctx.save();
    ctx.translate(x,mt+ph+16);
    ctx.rotate(-Math.PI/4);
    ctx.fillStyle="#1f2937";
    ctx.font="11px Tahoma";
    ctx.textAlign="right";
    ctx.fillText(String(it.mes_nome||""),0,0);
    ctx.restore();
  });
  ctx.textAlign="left";
  ctx.fillStyle="#2ecc71";
  ctx.fillRect(w-165,18,12,10);
  ctx.fillStyle="#333";
  ctx.font="11px Tahoma";
  ctx.fillText("Entradas",w-148,27);
  ctx.fillStyle="#3498db";
  ctx.fillRect(w-98,18,12,10);
  ctx.fillStyle="#333";
  ctx.fillText("SaÃ­das",w-81,27);
}
function fcxRenderPizza(canvas,titulo,itens,legendaTitulo){
  if(!canvas)return;
  const dados=(Array.isArray(itens)?itens:[]).filter(x=>fcxValorNumerico(x.valor)>0);
  if(!dados.length){fcxLimparCanvas(canvas,"Sem dados para o perÃ­odo selecionado.",titulo);return}
  const ctx=canvas.getContext("2d");
  const w=canvas.width,h=canvas.height;
  ctx.clearRect(0,0,w,h);
  ctx.fillStyle="#fff";
  ctx.fillRect(0,0,w,h);
  ctx.fillStyle="#111";
  ctx.textAlign="center";
  ctx.font="700 20px Tahoma";
  ctx.fillText(titulo,w/2,28);
  const cores=["#4f81bd","#c0504d","#9bbb59","#8064a2","#4bacc6","#f79646","#92a9bd","#bc8f8f","#7b9f35","#6e5f85","#2f5597","#8c2f39"];
  const total=Math.max(0.0001,dados.reduce((acc,x)=>acc+fcxValorNumerico(x.valor),0));
  const cx=Math.min(260,w*0.35),cy=Math.max(200,h*0.54),r=Math.min(140,Math.min(cx-20,h-cy-20));
  let ang=-Math.PI/2;
  dados.forEach((it,idx)=>{
    const frac=fcxValorNumerico(it.valor)/total;
    const a2=ang+frac*2*Math.PI;
    ctx.beginPath();
    ctx.moveTo(cx,cy);
    ctx.arc(cx,cy,r,ang,a2);
    ctx.closePath();
    ctx.fillStyle=cores[idx%cores.length];
    ctx.fill();
    if(frac>=0.04){
      const mid=(ang+a2)/2;
      const tx=cx+Math.cos(mid)*(r*0.58);
      const ty=cy+Math.sin(mid)*(r*0.58);
      ctx.fillStyle="#fff";
      ctx.font="700 11px Tahoma";
      ctx.textAlign="center";
      ctx.fillText(`${(frac*100).toFixed(1)}%`,tx,ty);
    }
    ang=a2;
  });
  const lx=Math.max(490,w*0.58),ly=86;
  ctx.textAlign="left";
  ctx.fillStyle="#111";
  ctx.font="700 12px Tahoma";
  ctx.fillText(legendaTitulo,lx,ly-12);
  dados.forEach((it,idx)=>{
    const y=ly+(idx*22);
    if(y>h-18)return;
    ctx.fillStyle=cores[idx%cores.length];
    ctx.fillRect(lx,y-9,12,12);
    ctx.fillStyle="#333";
    ctx.font="11px Tahoma";
    const nome=String(it.nome||"").slice(0,36);
    ctx.fillText(`${nome} - ${fcxFmtMoeda(it.valor)}`,lx+18,y+1);
  });
}
function fcxRenderGraficos(){
  if(!fcx)return;
  fcxRenderEvolucao();
  fcxRenderPizza(fcx.canvasGrupo,"Comparativo por Grupo Financeiro",fcxData?.comparativo_grupo||[],"Grupos");
  fcxRenderPizza(fcx.canvasCategoria,"Comparativo por Categoria Financeira",fcxData?.comparativo_categoria||[],"Categorias");
}
function fcxParams(){
  const params=new URLSearchParams();
  params.set("conta",(fcx.cboCC.value||"CLINICA").trim().toUpperCase());
  params.set("mes_inicio",String(Number(fcx.mesInicio.value||1)));
  params.set("mes_fim",String(Number(fcx.mesFim.value||12)));
  params.set("ano_inicio",String(Number(fcx.anoInicio.value||new Date().getFullYear())));
  params.set("ano_fim",String(Number(fcx.anoFim.value||new Date().getFullYear())));
  params.set("tipo_grupo",fcx.cboTipoGrupo.value||"CRÃ‰DITO");
  params.set("tipo_categoria",fcx.cboTipoCategoria.value||"CRÃ‰DITO");
  return params;
}
function fcxCanvasAtivo(){
  if(!fcx)return null;
  if(fcx.abaAtual==="grupo")return{canvas:fcx.canvasGrupo,titulo:"Comparativo por Grupo Financeiro"};
  if(fcx.abaAtual==="categoria")return{canvas:fcx.canvasCategoria,titulo:"Comparativo por Categoria Financeira"};
  return{canvas:fcx.canvasEvolucao,titulo:"Desempenho do Fluxo de Caixa"};
}
async function fcxCarregarDados(){
  if(!fcx)return;
  const params=fcxParams();
  const {res,data}=await requestJson("GET",`/financeiro/fluxo-caixa?${params.toString()}`,undefined,true);
  if(!res.ok){window.alert(data.detail||"Falha ao carregar anÃ¡lise de fluxo de caixa.");return}
  fcxData=data||{};
  fcxRenderGraficos();
}
function fcxImprimir(){
  const ativo=fcxCanvasAtivo();
  if(!ativo||!ativo.canvas){window.alert("NÃ£o hÃ¡ grÃ¡fico para imprimir.");return}
  const periodo=`PerÃ­odo: ${fcx.anoInicio.value||""} a ${fcx.anoFim.value||""}`;
  const conta=fcx.cboCC.value||"";
  const dataEmissao=new Date().toLocaleString("pt-BR");
  const img=ativo.canvas.toDataURL("image/png");
  const html=`<!doctype html><html lang="pt-BR"><head><meta charset="utf-8"><title>${esc(ativo.titulo)}</title><style>body{font-family:Arial,sans-serif;color:#111;padding:20px}h1{font-size:22px;margin:0 0 8px;text-align:center}.meta{text-align:center;font-size:13px;margin-bottom:16px}.graph{display:flex;justify-content:center}img{max-width:100%;height:auto;border:1px solid #d3dbe5}</style></head><body onload="window.print()"><h1>${esc(ativo.titulo)}</h1><div class="meta">${esc(periodo)} | Conta: ${esc(conta)}<br>Emitido em: ${esc(dataEmissao)}</div><div class="graph"><img src="${img}" alt="GrÃ¡fico"></div></body></html>`;
  const w=window.open("","_blank","noopener,noreferrer,width=980,height=720");
  if(!w){window.alert("NÃ£o foi possÃ­vel abrir a janela de impressÃ£o.");return}
  w.document.open();
  w.document.write(html);
  w.document.close();
}
function fcxFechar(){
  if(!fcx)return;
  fcx.panel.classList.add("hidden");
  workspaceEmpty.classList.remove("hidden");
}
async function fcxAbrir(){
  fcxEnsureUI();
  hideAllPanels();
  ensurePanelChrome(fcx.panel);
  fcx.panel.classList.remove("hidden");
  workspaceEmpty.classList.add("hidden");
  fcx._abrirAba("evolucao");
  await fcxCarregarDados();
  footerMsg.textContent="MÃ³dulo AnÃ¡lise de fluxo de caixa aberto.";
}
