async function unidadeCarregarTiposLogradouroV2(){
  const tiposTeste=["Tipos de logradouro","Tipo de logradouro","Logradouro","EndereÃ§o","Endereco"];
  for(const tipo of tiposTeste){
    try{
      const {res,data}=await requestJson("GET",`/cadastros/auxiliares?tipo=${encodeURIComponent(tipo)}`,undefined,true);
      if(!res.ok||!Array.isArray(data))continue;
      const itens=data
        .map(item=>String(item?.codigo||item?.descricao||"").trim())
        .filter(Boolean);
      if(itens.length)return Array.from(new Set(itens));
    }catch{}
  }
  try{
    const viaAux=await materiaisCarregarAuxTipo("Tipos de logradouro");
    const itens=(Array.isArray(viaAux)?viaAux:[]).map(x=>String(x||"").trim()).filter(Boolean);
    if(itens.length)return Array.from(new Set(itens));
  }catch{}
  return [];
}
