async function anamneseExcluirPergunta(){const item=anamneseSelecionado();if(!item){window.alert("Selecione uma pergunta.");return}if(!window.confirm(`Eliminar a pergunta ${item.numero}?`))return;const{res,data}=await requestJson("DELETE",`/anamnese/perguntas/${item.id}`,undefined,true);if(!res.ok){window.alert(data.detail||"Falha ao eliminar pergunta.");return}await anamneseCarregarPerguntas()}
async function anamneseRenumeraPerguntas(){if(!anamneseQuestionarioSelId){window.alert("Selecione um questionÃƒÂ¡rio.");return}const{res,data}=await requestJson("POST",`/anamnese/questionarios/${anamneseQuestionarioSelId}/renumerar`,{},true);if(!res.ok){window.alert(data.detail||"Falha ao renumerar perguntas.");return}await anamneseCarregarPerguntas()}
function anamneseVincularEventos(){if(!anamneseCfg||anamneseCfg.panel.dataset.bound==="1")return;anamneseCfg.panel.dataset.bound="1";anamneseCfg.tbody.addEventListener("click",ev=>{const tr=ev.target.closest("tr[data-id]");if(!tr)return;anamneseSelId=Number(tr.dataset.id||0)||null;anamneseRender()});anamneseCfg.cboQuestionario.addEventListener("change",async ev=>{anamneseQuestionarioSelId=Number(ev.target.value||0)||null;await anamneseCarregarPerguntas()});anamneseCfg.btnNovo.addEventListener("click",()=>anamneseAbrirModalQuestionario("novo"));anamneseCfg.btnEditar.addEventListener("click",()=>{if(!anamneseQuestionarioSelecionado()){window.alert("Selecione um questionÃƒÂ¡rio.");return}anamneseAbrirModalQuestionario("editar")});anamneseCfg.btnExcluir.addEventListener("click",anamneseExcluirQuestionario);anamneseCfg.btnImprimir.addEventListener("click",()=>window.alert("Imprimir questionÃƒÂ¡rio: em planejamento."));anamneseCfg.btnFechar.addEventListener("click",()=>{anamneseCfg.panel.classList.add("hidden");workspaceEmpty.classList.remove("hidden")});anamneseCfg.btnNovaPergunta.addEventListener("click",()=>anamneseAbrirModalPergunta("novo"));anamneseCfg.btnAlterarPergunta.addEventListener("click",()=>{if(!anamneseSelecionado()){window.alert("Selecione uma pergunta.");return}anamneseAbrirModalPergunta("editar")});anamneseCfg.btnExcluirPergunta.addEventListener("click",anamneseExcluirPergunta);anamneseCfg.btnRenumera.addEventListener("click",anamneseRenumeraPerguntas);anamneseCfg.modalQCancelar.addEventListener("click",anamneseFecharModalQuestionario);anamneseCfg.modalQOk.addEventListener("click",anamneseSalvarQuestionario);anamneseCfg.modalQBackdrop.addEventListener("click",ev=>{if(ev.target===anamneseCfg.modalQBackdrop)anamneseFecharModalQuestionario()});anamneseCfg.modalPCancelar.addEventListener("click",anamneseFecharModalPergunta);anamneseCfg.modalPOk.addEventListener("click",anamneseSalvarPergunta);anamneseCfg.modalPBackdrop.addEventListener("click",ev=>{if(ev.target===anamneseCfg.modalPBackdrop)anamneseFecharModalPergunta()})}
async function anamneseAbrir(){anamneseEnsureUI();anamneseVincularEventos();hideAllPanels();ensurePanelChrome(anamneseCfg.panel);anamneseCfg.panel.classList.remove("hidden");workspaceEmpty.classList.add("hidden");await anamneseCarregarQuestionarios();await anamneseCarregarPerguntas();footerMsg.textContent="ConfiguraÃƒÂ§ÃƒÂ£o de anamnese aberta."}

